PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE geopoints (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  lat REAL NOT NULL,
  lng REAL NOT NULL,
  description TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL,
  approved_at TEXT,
  approved_by TEXT
, submitted_by_name TEXT, submitted_by_email TEXT, submitted_by_ip TEXT);
CREATE INDEX idx_geopoints_location ON geopoints(lat, lng);
CREATE INDEX idx_geopoints_slug ON geopoints(slug);
