INSERT INTO geopoints VALUES('8b98Bdb9hXRIdpgc178MyO','Grădina Revoluției','grdina-revoluiei',44.438711350403594,26.098001003265384,'Grădina Revoluției este despre a da înapoi oamenilor un spațiu central, astăzi pierdut între mașini și beton. Vrem ca această piață să redevină un loc public autentic: deschis, plin de viață, unde rezonanța istorică îmbogățește experiența prezentă și conectează comunitatea.','2025-08-02T14:01:48Z','2025-08-02T14:11:45Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('8b98Bdb9hXRIdpgc178PXO','Pietonala Obor','pietonala-obor',44.449489634143085,26.126968860626224,'Într-un astfel de loc, cu trafic pietonal de zeci de mii de oameni zilnic, este necesar să facem o alegere: oare strada care face legătura dintre nodul de transport public Obor (metrou + tramvai + STB) și intrarea în piața Obor este folosită la potențialul maxim drept o parcare sau o stradă pietonală, verde și curată ar aduce bucurie miilor de oameni care calcă pragul Oborului zilnic?','2025-08-02T14:03:33Z','2025-08-02T14:12:02Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('8b98Bdb9hXRIdpgc178bcE','Piața Libertății','pa-libertii',44.41837714692473,26.095050573349003,'În cadrul celui de-al III-lea apel de idei am lansat provocarea de a găsi un spațiu pentru comunitate în jurul Fântânii Zodiac, aflată în Pța. Libertății la intrarea în Parcul Carol. Aici avea loc festivalul Luna Bucureștilor, cel mai mare și atractiv festival interbelic din România. Obiectivul apelului a fost legarea Fântânii de Parc și crearea de infrastructură necesară pentru viața urbană. ','2025-08-02T14:05:47Z','2025-08-02T14:12:31Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('LJJ2dPVFKx2EhGiZC9F58k','Calea Victoriei - pietonală permanentă ','calea-victoriei-pietonal-permanent-',44.4433085843223,26.093022823333744,'S-a ajuns prea departe. Avem 1.5 milioane de vehicule înmatriculate în București iar dacă vom continua să punem mașina pe primul loc, acest număr va crește în continuare.','2025-08-02T14:11:17Z','2025-08-02T14:12:45Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('LJJ2dPVFKx2EhGiZC9Es38','Grădina Episcopiei ','grdina-episcopiei-',44.44022825335919,26.096767187118534,'Recuperarea domeniului public pentru pietoni, amenajarea zonei Pieței George Enescu și redescoperirea istoriei orașului dinaintea influențelor occidentale','2025-08-02T14:08:58Z','2025-08-02T14:13:04Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('LJJ2dPVFKx2EhGiZC9EnaE','Pietonale între parcuri','pietonale-ntre-parcuri',44.44451099198168,26.103826761245728,'Pietonale între Parcuri: Grădina Icoanei - Parcul Ioanid reprezintă cercetarea de alternative pentru a transforma spațiul dintre cele două parcuri monument istoric într-un loc prietenos cu pietonul','2025-08-02T14:07:03Z','2025-08-02T14:13:19Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('57dhSchUu5juggpLOl3Xor','Niro Voluntari','niro-voluntari',44.48525551461921,26.17601571525728,'Ducem lipsă de parcuri pe această zonă, mi-aș dori să am și eu un parc în care să ies să mă plimb și în care să îmi plimb cățelul.','2025-08-04T17:55:31Z','2025-08-04T20:27:14Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('M9DHw4PongwVZywLd5VoDr','În spatele blocului','n-spatele-blocului',44.418234561930554,26.136322393931632,'Mi-aș dori ca parcarea din spatele blocului să devină o grădină interioară unde toți copiii să se joace și adulții să poată forma o comunitate ','2025-08-04T18:04:33Z','2025-08-04T20:27:49Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('EnCrLFNjTHniG63frUMO2y','Turnul de apa cu cafenea','turnul-de-apa-cu-cafenea',44.42334876264711,26.047599634621296,'Un turn de apa vechi, ramas printre blocuri ar putea deveni un nou reper în cartier. Cu o cafenea si un mic amfiteatru','2025-08-04T19:01:39Z','2025-08-04T20:28:19Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNcpJ4D','Natură lângă statui ','natur-lng-statui-',44.43501836727926,26.10107302660254,'Să se refacă zona astfel încât să fie integrate niște elemente de natură în piață și în zonă. Aceste elemente să fie niște copăcei și zone verzi care să facă zona mai primitoare ','2025-08-04T20:25:46Z','2025-08-04T20:28:51Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('TeE7UnMQqe1hXXnmyPlSLq','Transformarea parcări într-o zonă verde ','transformarea-parcri-ntr-o-zon-verde-',44.42729059063863,26.09099507331848,'Să fie o peninsulă de natură care va consta prin transformarea parcări într-un spațiu verde și bulevardul respectiv să fie obligat să facă acel semicerc. Astfel bucata de drum dintre semicerc și trotuarul din fața Palatului Parlamentului să fie unit','2025-08-04T20:20:12Z','2025-08-04T20:29:13Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('TeE7UnMQqe1hXXnmyPlKRi','Drumul Gura Crivatului - sansa spre o zona mai verde','drumul-gura-crivatului-sansa-spre-o-zona-mai-verde',44.41196481419797,26.192457675933838,'Un parc- ceea ce lipseste in zona ','2025-08-04T20:18:56Z','2025-08-04T20:29:34Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('TeE7UnMQqe1hXXnmyPl9ew','Intersecția mea','intersecia-mea',44.43695653360584,26.168417931039585,'Să fie mai integrată cu natura și să fie o legătura între parc și transportul în comun capătul de autobuz și metrou ','2025-08-04T20:15:28Z','2025-08-04T20:29:54Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('PE1x5BxjaGOX7GYXnfAj2x','Orășelul copiilor','orelul-copiilor',44.40015146011856,26.10859036445618,replace('Mi-aș dori ca parcul Tineretului să fie un parc de-a întregul, nu unul care este segmentat in două: un parc verde și o zonă de bâlci cu zgomot și kitsch-uri.\nSunt curios cum ar arăta parcul Tineretului cu un Orășel al copiilor modernizat: fără tiribombe și gherete ambulante. Un parc verde cu spații de joacă adecvate, eliberat de comerțul ambulant de acolo.','\n',char(10)),'2025-08-04T20:02:30Z','2025-08-04T20:30:14Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNcpi6h','Piața Lahovari ','piaa-lahovari-',44.4455894123555,26.0999500750404,'Să se facă toată zona pietonală și să se mențină doar niște benzi de autobuz. Zona pietonală va fi o continuare a zonei de la piața romană până la parcul icoanei. Deasemenea va fii făcut un drum special de acces pentru spital.','2025-08-04T20:29:56Z','2025-08-04T20:30:30Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('PE1x5BxjaGOX7GYXnfA6Nj','Intersecția Constantin Brâncoveanu','intersecia-constantin-brncoveanu',44.398222261594114,26.10981345176697,replace('In prezent e o insulă de căldură și zgomot provocată de mașini care circulă cu viteză mare. Mi-aș dori următoarele:\n1. Reducerea numărului de benzi și spațiu dedicat mașinilor.\n2. Plantarea mai multor spații verzi și copaci înalți pentru umbrire.\n3. Refacerea trecerilor de pietoni în unele mai largi care să aibă continuitate fără să fie vizibilă segmentarea prezentă de stația de tramvai.','\n',char(10)),'2025-08-04T19:56:35Z','2025-08-04T20:30:51Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('PE1x5BxjaGOX7GYXnf9vkN','Parcul Bibliotecii Naționale','parcul-bibliotecii-naionale',44.424751661596815,26.114480495452884,'Având în vedere dimensiunea mare a terenului, consider ca un parc ar fi benefic din mai multe puncte de vedere. În primul rând acest parc ar putea avea spații verzi extinse cu numeroși copaci, astfel asigurând o atmosferă  plăcută. De asemenea parcul ar putea avea terenuri de sport (paddle, tenis, baschet) funcționale, fiind umbră, acestea pot fi folosite și ziua, iar un outdoor gym ar adăuga un plus de valoare. Un ultim punct ar fi spațiile de promenadă, acestea pot fi fie zone mai liniștite în care elevii / stundetii care vin la bibliotecă, pentru a invata, pot face plimbări în pauze astfel curățându-și mintea, dar pot fi și spații de promenadă mai active dpdv cultural (zone de concerte, zone de mici târguri, etc) ','2025-08-04T19:54:16Z','2025-08-04T20:31:11Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNckvy3','Parcare Mariuca 10','parcare-mariuca-10',44.38404625712686,26.133631467819217,'Parcarea din spatele blocului nu ar trebui sa fie un spatiu arid, dedicat exclusiv parcarii masinilor, ci un spatiu viu, in care copiii sa se poata juca, vecinii sa poata socializa (poate chiar tine sedintele de bloc aici), mamele sa isi poata plimba copiii. Ne dorim copaci printre locurile de parcare, banci pentru oameni, spatii destinate tomberoanelor astfel incat ele sa nu mai stea in drum.','2025-08-04T19:32:38Z','2025-08-04T20:31:32Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNckuxZ','Rond. + strazi adiacente Sala Omnia','rond-strazi-adiacente-sala-omnia',44.437977941500876,26.100018024444584,'Ar putea fi conectate pt pietoni la ceea ce este acum Parcarea Revolutiei. ','2025-08-04T19:32:32Z','2025-08-04T20:31:54Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('TeE7UnMQqe1hXXnmyPhKQU','Parcare Piata Reevolutiei','parcare-piata-reevolutiei',44.43823839733923,26.09823703765869,'Pietonal, verde, relaxant','2025-08-04T19:31:22Z','2025-08-04T20:32:08Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('TeE7UnMQqe1hXXnmyPhBBu','Mariuca 10','mariuca-10',44.38333317062255,26.13384604454041,'Stradutele mici dintre blocuri ar trebui sa fie prietenoase cu pietonii si mai ales cu mamele care ies cu copiii la plimbare. Momentan trotuarele au fost ingustate atat de mult pentru a face loc masinilor si parcarilor ca nu mai poti merge 2 persoane pe trotuar in tandem, nici in acelasi sens de mana, cu un carucior, nici in sensuri opuse. Au fost puse borduri foarte mari, trotuarele au fost reduse la jumate si puse sa ocoleasca foarte mult pentru a face parcari. Ne-am dori troatuare largi, imprejmuite de copaci pentru umbra, fara borduri supradimensionate si in loc de stalpisori care sa blocheze masinile din a parca, copaci, care sa indeplineasca acelasi scop, plus cel de umbra, purificare a aerului si casa pentru pasari','2025-08-04T19:29:49Z','2025-08-04T20:32:25Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('TeE7UnMQqe1hXXnmyPg22k','Piata iosif sava','piata-iosif-sava',44.43906614515312,26.09248638153076,'Sa se valorifice piata, sa se scape de masini','2025-08-04T19:13:07Z','2025-08-04T20:32:39Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNciSTH','Lizeanu','lizeanu',44.452776120110386,26.120145320892334,'Strada inchisa, plina de cafenele, cu deschidere catre moara lui Assan','2025-08-04T19:05:47Z','2025-08-04T20:33:00Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('M9DHw4PongwVZywLd5d2GZ','Teren ','teren-',44.42961358817398,26.09572096836211,'Eliminarea panourilor publicitare de pe terenul (nebetonat) de lângă parcare și plantarea de arbori pe tot acest teren. ','2025-08-04T18:49:14Z','2025-08-04T20:33:46Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNcgZnZ','Biserica Scaune','biserica-scaune',44.435013259408315,26.105167865753177,'E o zona care arata dezolant, e un spatiu de parcare, nu e verdeata (iar in zona nu exista niciun loc de joaca sau vreun mic parc macar). Ar putea fo facut in mic parculet unde sa poata iesi lumea cu copiii. Mergea eventuam si un mic amfiteatru pt concerte de muzica clasica de ex, doar ca in fata e spitalul si nu cred ca e voie. ','2025-08-04T18:39:50Z','2025-08-04T20:34:29Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('57dhSchUu5juggpLOlC1zJ','Soseaua Gheorghe Ionescu Sisesti','soseaua-gheorghe-ionescu-sisesti',44.49356657962081,26.075191497802738,'Din 4 benzi, 2 pe sens,  si trotuare utilizate drept parcari, nefiind locuri de parcare in zona, in 2 benzi, 1 pe sens, 1 banda pe fiecare sens, pentru biciclete, prin eliminarea a cate 1 banda auto, trotuare libere, locuri de joaca pentru copii, acces la lacul Grivita pentru cetateni unde sa poata desfasura activitati de agrement. Zona are un potential urias prin lacul adiacent si padurea Baneasa ce poate avea piste se bicicleta si trekking fara a fi nevoie de asfalt. ','2025-08-04T18:39:11Z','2025-08-04T20:34:45Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('M9DHw4PongwVZywLd5cKLL','Parcul Patrat','parcul-patrat',44.43668330554744,26.11685156822205,'E un mic parculet cu locuri de joaca pt copii - in jur e depozit de masini. In zona sunt restaurante, un teatru - poate fi transformat prin blocarea locurilor de parcare cu parkleturi, unde se pot extinde terase cu verdeata. Ar fi benefic pt zona si pt afaceri. ','2025-08-04T18:36:54Z','2025-08-04T20:35:03Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('M9DHw4PongwVZywLd5c0Nv','Lascar/Italiana','lascaritaliana',44.43847587076822,26.10775351524353,'E o intersectie de mai multe stradute ingropata in masini. Ar putea fi inverzita cu copacei si adaugat ceva mobilier urban modern - in zona e un liceu si copiii ies sa isi mai ia sucuri, sunt deja cafenele si take aways, ar fi minunat sa aiba lumea si unde sta. ','2025-08-04T18:34:22Z','2025-08-04T20:35:50Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNcqDoX','Piața Spaniei ','piaa-spaniei-',44.44586259993542,26.107939481844372,'Piața Spaniei va urma să devină pietonală. Deasemenea se vor face zone cu mese și băncuțe ca oamenii din vecinătate să stea și să joace un șah, table sau doar să se relaxeze.','2025-08-04T20:32:42Z','2025-08-04T20:36:09Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('57dhSchUu5juggpLOlAz2F','Coanda/Iorga','coandaiorga',44.4476293527388,26.093022823333744,'Acum sunt parcate masini intr-o intersectie intre blocuri. Cred ca s-ar potrivi sa fie un mic spatiu verde, evwntual cu o fantana la nivelul solului, copaci taiati rotund in cerc (e o specie care poate fi taiata astfel incat sa arate ca un cerc si cred ca pot fi plantati si in ghivece f mari). Sub copaci - bancute (model fara spatar, doar lemn)','2025-08-04T18:30:15Z','2025-08-04T20:37:04Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('M9DHw4PongwVZywLd5a6tP','Piata giulesti','piata-giulesti',44.46622357951638,26.034931439566652,'Sa transforme piata in spațiu verde. Sunt de asemenea multe curți abandonate care ar putea fi transformate in mici parcuri','2025-08-04T18:19:35Z','2025-08-04T21:00:59Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNcckBn','Spațiu lângă Liceul Hristo Botev ocupat de mașini','spaiu-lng-liceul-hristo-botev-ocupat-de-maini',44.445377499398276,26.08427882194519,replace('PROBLEMA: La intersectia dintre Calea Grivitei si strada Semicercului, langa liceul bilingv Hristo Botev, exista un spatiu pietonal de dimensiuni mari care este ocupat de ani de zile de masini. Acesta desi este un spatiu pietonal, el functioneaza ca parcare auto ilegala. Nu exista marcaje rutiere sau indicator rutier care sa permita parcarea auto. Trecerile de pietoni sunt blocate de masini. In zona exista cafenele, restaurante, pub-uri si magazine de materiale pentru arta. Limita de viteza auto este de 30 km/h pe acest segment a Caii Victoriei, insa nu este respectat. Au existat 3 accidente in zona in ultimul an.\n\nPROPUNERE: Transformat spatiul pietonal pe care sunt parcare masini intr-un spatiu sigur cu oamenii, mai ales ca exista liceu in zona, si in acelasi timp adoptate masuri si pentru siguranta pietionala si rutiera pe segmentul de strada care include cafenele, restaurante, magazine, liceu. Treceri de pietoni si trotuare sigure, spatii verzi, viteza auto redusa, spatii pentru elevi si profesori langa liceu, etc.','\n',char(10)),'2025-08-04T18:13:45Z','2025-08-04T21:01:26Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNccU8r','Piațetă Biserica Enei','piaet-biserica-enei',44.436897803427556,26.09933137893677,'Desființarea parcării și amenajarea unui spațiu public cu funcțiune de loc pentru odihnă și socializare, adaptat în contextul schimbărilor climatice - cu spații verzi și biodiversitate, care să servească drept loc de poposit și de socializat pentru trecători, pentru enoriașii care vin la biserică și pentru toți studenții din zona - de la Arhitectura și de la UniBuc.','2025-08-04T18:13:05Z','2025-08-04T21:02:08Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNcqUn9','Metrou Costin Georgian ','metrou-costin-georgian-',44.435335015128715,26.16917610168457,'Să se schimbe locația ușilor de acces către metrou astfel încât să poți traversa strada "pe la metrou" și când acesta este închis','2025-08-04T20:36:21Z','2025-08-04T21:03:02Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('57dhSchUu5juggpLOl5knD','Intersecția Dorobanti -Iancu de Hunedoara ','intersecia-dorobanti-iancu-de-hunedoara-',44.45325505231794,26.098264445507567,'Un parculet umbros ','2025-08-04T18:06:04Z','2025-08-04T21:03:18Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('57dhSchUu5juggpLOl5T5L','Piațetă la intersecția Episcopiei x Constantin Esarcu','piaet-la-intersecia-episcopiei-x-constantin-esarcu',44.44154761748929,26.096788644790653,'Desființarea parcării și amenajarea unui spațiu public tip piațetă, poate cu o fântână sau o sculptură/statuie, locuri de stat, câteva alveole verzi. Toate clădirile din jur au o arhitectură prea spectaculoasă pentru ca locul să rămână doar o parcare. Merge bine cu pietonizarea străzii Constantin Esarcu, pentru crearea unei legături cu străzile frumoase din spatele Ateneului. ','2025-08-04T18:04:48Z','2025-08-04T21:03:48Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('68DGtxQ7r7K1opVUNcssTR','Titan Pallady','titan-pallady',44.41140534736817,26.195697784423828,'Șanse de dezvoltare durabilă și pentru constructori și pentru locuitori ','2025-08-04T21:04:21Z','2025-08-04T21:05:08Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('Qn7XvoKw9OlkLAmyumqtrz','Natiunile Unite','natiunile-unite',44.42960443378369,26.096037626266483,'Intr un Bucuresti in care Calea Vicotriei e pietonala, aceasta zona ramane un vis urat - cate doua trei benzi de masini din toate directiile, parcari, trotuare inguste si impartite cu pista de biciclete pe alocuri, 0 umbra, iar spatiile verzi si cladirile sunt lasate in paragina. Mi as dori recionfigurarea intregii intersectii avand ca prioritate pietonii si cladirile emblematice din jur, nu infrastrctura pentru masini - trotuare largi, umbrite si fara panouri publicitare - o zona care sa faca tranzitia la Calea Victoriei una fireasca, nu o provocare.','2025-08-04T22:09:10Z','2025-08-05T07:48:12Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('hAuuJ3dDLNuCTVH29f9BgV','Strada Biruintei','strada-biruintei',44.36549551511036,26.153941154479984,'Copaci și trotuare vă rugăm!','2025-08-05T07:43:47Z','2025-08-05T07:48:38Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('hAuuJ3dDLNuCTVH29er2YW','Intersecție Șoseaua Viilor - ctin Istrati','intersecie-oseaua-viilor-ctin-istrati',44.41146665906269,26.088752746582035,'Mai mult spațiu verde - e o intersecție plină de stații de tramvai unde vara e imposibil să aștepți transportul în comun din cauza lipsei de umbră și a căldurii. ','2025-08-05T06:12:48Z','2025-08-05T07:48:53Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('76QQV0zlptBPiZCfYvXleR','Toată zona Unirii ','toat-zona-unirii-',44.425873124927534,26.117699146270752,'Copaci, ca să nu mai simți ca treci printr-un cuptor ','2025-08-05T07:42:23Z','2025-08-05T07:49:04Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('9i0p9EFjZdEl34M0vzBbPk','Trotuar Piata Chibrit','trotuar-piata-chibrit',44.471092480715676,26.05156660079956,'As dori ca masinile sa nu mai parcheze pe trotuar in zona Pietei Chibrit','2025-08-05T08:11:07Z','2025-08-05T10:31:59Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('76QQV0zlptBPiZCfYvtziR','Bd Ferdinand 1','bd-ferdinand-1',44.43903107212907,26.118301012254165,'Amenajarea unei benzi de autobuz pe ambele sensuri ale bulevardului Ferdinand 1. Acesta are aprox 2,1km dintre care 1,5km sunt cu 2 benzi/sens, iar prima este ocupată de mașini parcate! Zona este foarte aglomerată și astfel se poate încuraja mersul cu autobuzele 69 și 85, deoarece timpul va fi redus semnificativ. ','2025-08-05T09:41:26Z','2025-08-05T10:32:22Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('9i0p9EFjZdEl34M0vzbDnB','Strada Ciresului','strada-ciresului',44.434331437860486,26.1272021734345,replace('Plantarea de copaci pe trotuare, stanga dreapta pentru o umbri intreaga strada.\nDe luat exemplu strada Episcopul Ilarion din apropiere','\n',char(10)),'2025-08-05T10:27:38Z','2025-08-05T10:32:35Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('76QQV0zlptBPiZCfYw5VzR','Piata Baneasa si Complex Romaero','piata-baneasa-si-complex-romaero',44.49421709726685,26.084815263748172,'Zona comerciala ce ar putea fi revigorata prin o mica renovare, cladirile deja exista. Este nevoie de acces putin mai facil pietonal si crearea unor spatii deschise pentru zone de relaxare','2025-08-05T10:31:35Z','2025-08-05T10:32:54Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('9i0p9EFjZdEl34M0vzbNDR','Horia Macelariu X Promoroaca x Bilciuresti','horia-macelariu-x-promoroaca-x-bilciuresti',44.490107234483794,26.086692810058597,'Este o zona care s-a dezvoltat cu blocuri noi, destul de interesante ca aspect, in schimb infrastructura a ramas in urma - strazi fara trotuare, strazile au sens dublu dar de obicei sunt parcate masini - s-ar putea trece la sens unic, spatii verzi reduse/inexistente.','2025-08-05T10:30:17Z','2025-08-05T10:33:18Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('hAuuJ3dDLNuCTVH29fYEjS','Aleea Lerești ','aleea-lereti-q',44.401945887200355,26.051265265754886,'In zona aceasta in fiecare seara sunt foarte mulți copii care ies la joaca, spațiu exista, copaci sunt însă totul este ne îngrijit. Se pot face spatii verzi pentru comunitate.','2025-08-05T10:12:28Z','2025-08-05T10:33:45Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('9i0p9EFjZdEl34M0vzXCMb','Aleea Lerești ','aleea-lereti-2',44.4023446192748,26.052508670752648,'Între blocurile acestea se afla un mini "parc", dat in folosul comunității dat fiind faptul ca deja exista niste alei. O propunere ar fii deblocarea cailor de acces si investit pentru folosință, alei, bănci.','2025-08-05T10:10:47Z','2025-08-05T10:34:05Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('9i0p9EFjZdEl34M0vzWc8r','Aleea Lerești ','aleea-lereti-',44.40232182130082,26.053337517816953,'Cred ca acele construcții pot fi demolate si transformate intr-o zona verde pentru socializare si recreere atât de necesară acestui sector.','2025-08-05T10:05:34Z','2025-08-05T10:34:22Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('76QQV0zlptBPiZCfYw0JKR','Str. Antiaeriana ','str-antiaeriana-1',44.41552442607878,26.056879534147587,'Construcții vechi, periculoase atât pentru pietoni cat si pentru mașinile care tranzitează. Se poate transforma intr-o zona verde.','2025-08-05T10:06:58Z','2025-08-05T10:34:45Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('hAuuJ3dDLNuCTVH29fXlsQ','Str. Antiaeriana ','str-antiaeriana-',44.40990611464851,26.053757454991548,'Știind faptul ca este terenul Mapn, după modelul ștrandului Tei, cred ca se poate face o sugestie de parc Mapn având în vedere ca zona aceea este locuita de foarte mulți militari.','2025-08-05T10:08:33Z','2025-08-05T10:35:04Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('76QQV0zlptBPiZCfYvvFmR','Amenajarea unei piste de biciclete și unei benzi de autobuz ','amenajarea-unei-piste-de-biciclete-i-unei-benzi-de-autobuz-',44.43421082123407,26.067305799330168,'Bd. Eroii Sanitari poate fi redus la o bandă pentru mașini, o bandă de autobuz, o pistă de biciclete și un culoar verde cu lățimea de 1m. Astfel se încurajează transportul alternativ.','2025-08-05T09:43:45Z','2025-08-05T10:35:17Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('hAuuJ3dDLNuCTVH29fOXbX','Bariere acustice pentru parcul kiseleff ','bariere-acustice-pentru-parcul-kiseleff-',44.45694221865807,26.08480453491211,'Parcul este extrem de zgomotos. Niste garduri verzi cu bariere acustice ar fi ideale pentru a imbunatati atmosfera.','2025-08-05T09:17:26Z','2025-08-05T10:35:39Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('hAuuJ3dDLNuCTVH29fLxay','Palatul ghica intre 3 parcuri','palatul-ghica-intre-3-parcuri',44.46536540687396,26.127634048461914,'Acum e o intersectia care se tot mareste si desparte Parcul plumbuita de parcul tei si de pajistea petricani. Aceste 3 parcuri merita mai mult decat o intersectie disfunctionala in varf de deal cu o benzinarie. Acolo este si palatul ghica care este practic ignorat in circuitul istoric al orasului. Ar fi frumos daca soseaua ar fi ingropata si ar fi o pietonala pe deasupra.','2025-08-05T09:10:25Z','2025-08-05T10:35:53Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('9i0p9EFjZdEl34M0vzHiPs','Fost centru educational (scoala + gradinita)','fost-centru-educational-scoala-gradinita',44.42351214470687,26.128910779953006,'Este un spatiu in paragina si imi este frica ca este vanat de rechinii imobiliari. Cartierul nu are suficiente spatii verzi si cele mai apropiate parcuri sunt Izvor si Parcul Carol.','2025-08-05T08:52:52Z','2025-08-05T10:36:15Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('76QQV0zlptBPiZCfYw64VR','Parcare intre Uni si Mincu','parcare-intre-uni-si-mincu',44.43582530615316,26.10051155090332,'Cum ar arata oare, ca in loc de parcarea de pe strada Strada Edgar Quinet intre Universitate si Ion Mincu sa fie o frumoasa zona pietonala, un parc cu bancute? ne inghesuim studenti de la ~20 facultati pe un trotuar minuscul, e foarte greu sa te deplasezi pentru ca este deja ocupat de alti studenti in pauza (care nu au unde altundeva sa iasa) si masini parcate cu botul pe trotuar, ca nu le ajunge toata strada','2025-08-05T10:34:31Z','2025-08-05T10:36:31Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('9i0p9EFjZdEl34M0vzGJ6M','Amenajarea Podului din fata Operei Nationale','amenajarea-podului-din-fata-operei-nationale',44.434499978758566,26.078217029571537,'Podul este acum o mare parcare care ruineaza privelistea spre unul din cele mai importante monumente culturale ale orasului si face intreaga zona neatractiva. In plus, se poate extinde cu o eventuala viitoare zona de promenada pe langa Dambovita.','2025-08-05T08:41:13Z','2025-08-05T10:36:44Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('hAuuJ3dDLNuCTVH29fenOR','Parcul Vagonului','parcul-vagonului',44.4573710648712,26.11581087112427,'O stradă uitată din București. O fostă linie de tren dezafectată și un spațiu al nimănui. Poate deveni un parc liniar ca centru al unui cartier de case. ','2025-08-05T10:35:11Z','2025-08-05T10:36:57Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('9i0p9EFjZdEl34M0vzG33I','Strazi pietonale in extinderea Centrului Vechi','strazi-pietonale-in-extinderea-centrului-vechi',44.43321292685644,26.094739437103275,'Zona face parte din Centrul Vechi, dar se simte mult mai decuplata si neplacut de vizitat din cauza strazilor pline de masini.','2025-08-05T08:38:55Z','2025-08-05T10:37:12Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('76QQV0zlptBPiZCfYvgjmR','Parc istoric','parc-istoric',44.4572715115667,26.087497472763065,'Vila Filipescu-Brancoveanu si gradinile ei ar trebui sa fie vizitabile si parte a domeniului public in loc de sediu de partid. Vila trebuie ingrijita corespunzator, nu cu aparate de aer conditionat pe fatadele externe.','2025-08-05T08:37:53Z','2025-08-05T10:37:28Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('hAuuJ3dDLNuCTVH29fG3zY','Piata Victoriei','piata-victoriei',44.45226299550433,26.08506202697754,'O piata demna de o capitala Europeana, nu inca o parcare supraterana greu de traversat ca pieton. O Piata urbana cu verdeata si configurata mai bine pentru pietoni poate continua promenada pe Piata Victoriei cu bulevardele Kiseleff si Aviatorilor si extinde acest circuit al orasului, pe care turistii si locuitorii il pot face la pachet.','2025-08-05T08:36:23Z','2025-08-05T10:37:42Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('hAuuJ3dDLNuCTVH29ffqhY','Parcul Pantelimon','parcul-pantelimon',44.43638904538227,26.20050430297852,replace('Sa dispara parcarea de pe trotuarul de langa parc. Parcare unde scolile auto fac instructaj si unde politistii de la rutiera nu vad nimic in neregula cu asta cand au examen.\nIar despre parcul Pantelimon, a fost o oaza de verdeata, un parc semisalbatic. Acum este injumatatit, iar ce a ramas  este rascolit, defrisat si cu multi arbori uscati.','\n',char(10)),'2025-08-05T10:47:18Z','2025-08-05T16:26:46Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k6d9hZ','Bd. Theodor Pallady','bd-theodor-pallady',44.40539184411077,26.20756078716897,'Mijloace alternative de transport, spatii verzi accesibile pietonal, grădinițe și scoli în zonă.','2025-08-05T16:21:34Z','2025-08-05T16:27:01Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDx97X74','Depoul Bucurestii Noi','depoul-bucurestii-noi',44.47838832626241,26.044528484344486,'Doiresc o conexiune pietonala intre bulevardul Bucurestii noi si Strada Hrisovului.','2025-08-05T15:56:24Z','2025-08-05T16:27:23Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv76BbQd','Palatul Kretulescu','palatul-kretulescu',44.43973765498395,26.088677644729618,replace('Amenajare frumoasa in fata palatului Kretulescu in locul celor cateva locuri de parcare care uratesc zona si impiedica punerea palatului, una din cele mai frumoase cladiri din Bucuresti, in valoare.\nIdeal, palatul ar fi unit cu parcul Cismigiu, astfel incat sa devina un highlight al parcului precum in alte parcuri istorice din Europa (de exemplu palatul din parcul Łazienki din Varsovia).','\n',char(10)),'2025-08-05T14:22:05Z','2025-08-05T16:27:40Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k6Qm25','Dezvoltarea infrastructurii pentru tramvaie a Șoselei Nicolae Titulescu expropriind și lărgind în zona Străzii Iacob Felix și a Străzii Veronica Micle cu demolarea ruinelor și a furnalului din zona Spitalului Filantropia!','dezvoltarea-infrastructurii-pentru-tramvaie-a-oselei-nicolae-titulescu-expropriind-i-lrgind-n-zona-strzii-iacob-felix-i-a-strzii-veronica-micle-cu-demolarea-ruinelor-i-a-furnalului-din-zona-spitalului-filantropia',44.45213279899166,26.081081628799442,replace('Să evolueze și zona intersecției Șoseaua Nicolae Titulescu X Strada Iacob Felix care paradoxal are blocuri între 8 și 14 etaje cu peste 1000 de apartamente și mastodonți de sticlă dar linie de tramvai îngâtuită de anii 1960-1970,configurații șerpuite și îngâtuite pentru condus autospeciale pentru incendii,autogunoiere sau autobuze șu fundături la condiții urbanistice de secolul XXI cu infrastructură pentru tramvaie 100% separată de traficul auto,100% cu carosabil de minim 7 m lățime,cap-coadă cu trotuare pentru condus cărucioare pentru copii fără grija mașinilor și fără fundături!\n','\n',char(10)),'2025-08-05T14:15:35Z','2025-08-05T16:28:09Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k6QGUb','Parculet','parculet',44.42700066550583,26.05756180873438,'Acum e un spatiu napadit de buruieni, neluminat, unde bucurestenii isi parasesc fostele saltele.  Primaria sectorului 6 a plasat  o ghena ingropata intr-un colt, la cca 6 m de un bloc. Se pare ca ar fi in ingrijirea Complexului Sportiv National “Lia Manoliu”. Daca ar fi ingrijit, luminat si ar avea o alee pietruita care sa il strabata, ar fi o imensa imbunatatire. ','2025-08-05T14:07:56Z','2025-08-05T16:28:33Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('RQ60bUIkqADTmoQr6r96BH','Reamenajarea spațiului de parc','reamenajarea-spaiului-de-parc',44.435177833123475,26.073034484972386,'Refacerea porțiunii de parc și construirea unei fântâni.','2025-08-05T14:07:04Z','2025-08-05T16:28:46Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k6PMun','Pocket Park - pentru odihnă și schimburi de plante','pocket-park-pentru-odihn-i-schimburi-de-plante',44.41525253167266,26.193573474884037,'Chiar și cu doar 2-3 locuri de parcare transformate într-un mic spațiu verde dotat cu băncuțe, am putea câștiga un prim loc de socializare pe o stradă cu mii de apartamente și zero spații verzi publice. Ar putea deveni spațiul în care comunitatea locală să se întâlnească pentru a muta discuțiile despre cartier în afara bulelor aferente fiecărui ansamblu rezidențial și unde periodic să avem mici evenimente care să ne facă viața mai frumoasă: schimburi de plante, citit de povești pentru copii, teatru de păpuși.','2025-08-05T13:51:17Z','2025-08-05T16:29:04Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k6OGN7','Zona proximitate palatul parlamentului','zona-proximitate-palatul-parlamentului',44.42896085746858,26.08491182327271,'Deschiderea zonei pentru Popor. Transformarea curtii in spatiu public, restrangerea perimetrului casei poporului','2025-08-05T13:33:30Z','2025-08-05T16:29:18Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k6MKer','Piata Unirii','piata-unirii',44.43304438224648,26.084032058715824,replace('odata cu reconstructia canalului de la Unirii si daramarea ramasitelor comuniste din centrul pietei ( asa zisele fantani arteziene) , s-ar putea reamenaja tot spatiul ca un mare parc, iar traficul reconfigurat intr-un mare sens giratoriu in jurul spatiului parcului. dpdv al traficului, s-ar elimina 3-4 intersectii, deci 3-4 semafoare mai putin, iar timpul pierdut prin ocolirea parcului ar fi astfel recastigat.... mai putine conflicte de trafic, mai putin timp pierdut.\n\niar pentru cine tine neaparat sa aibe arteziene, se poate pastra fantana principala, dar fara cele laterale bulevardului actual.\n\nun minus al acestui plan ar putea fi legat de legatura tramvaiului intre Dealul Mitropoliei si Sf Gheorghe.... dar si aici se poate gandi linia de tramvai in jurul parcului','\n',char(10)),'2025-08-05T13:02:30Z','2025-08-05T16:29:35Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('HTZndbBEBHPaOe1l0odXeI','Piața Sf. Gheorghe fără mașini','piaa-sf-gheorghe-fr-maini',44.432201651905174,26.104674339294437,'În "celebrul" KM 0 al capitalei, în afara de transportul în comun, serviciul de poliție/pompieri/ambulanță și aprovizionare, nu au ce căuta mașinile parcare fix lângă linia de tramvai. Spațiul oricum e sufocat total, ar trebui să fie pusă în valoare biserica și nu lipsa spațiului destinat pietonilor.','2025-08-05T12:12:59Z','2025-08-05T16:29:49Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('HTZndbBEBHPaOe1l0ococW','Parcul Unirii','parcul-unirii',44.438207755536155,26.097486019134525,replace('Zona pietonala si parc modern, cu 70% zona verde cu copaci mari umbrosi. Ca o oaza de relaxare, care protejeaza si ocreteste oamenii din interiorul parcului de zgomotul si agitatia de afara. Copacii actionand ca niste ziduri uriasi. O fortareata a linistii si relaxarii.\n\nNU pasaj supra-teran auto.\nideal NU trafic auto ','\n',char(10)),'2025-08-05T11:55:47Z','2025-08-05T16:30:06Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv75tu0v','Umbra pietonala in piata operei','umbra-pietonala-in-piata-operei',44.4342088623566,26.078968048095707,'pietonii au zero umbra in toata piata operei. Este ucigator sa treci zona pe jos.','2025-08-05T11:34:57Z','2025-08-05T16:30:22Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k6uGfF','Sere drumul cooperativei','sere-drumul-cooperativei2',44.40797945430784,26.025753021240238,'Dorim sa fie parc cu multe flori( sa rămâne florile din sere) dar sa fie un parc accesibil tuturor cetățenilor. ','2025-08-05T18:24:56Z','2025-08-05T19:05:40Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDx9jTk1','Plantare de copaci sau arbusti','plantare-de-copaci-sau-arbusti',44.42906045902845,26.06261730194092,'Poate ca nu e cea mai atractiva zona avand in vedere ca e inconjurata de o intersectie, dar aici deasupra metroului e doar iarba/gazon. E ingrozitor sa mergi pe acest trotuar din cauza galagiei de la masini. Daca s-ar face cateva alei pietruite cu bancute si spre strazi/bulevarde sa se planteze niste copaci sau macar niste arbusti pt a mai izola de galagia strazii ar putea deveni un loc frumos. Intersectia aia este infernala pe bicicleta, daca s-ar putea sa treaca si o pista de biciclete pe acolo pt a evita intersectia ar fi minunat. ','2025-08-05T18:18:36Z','2025-08-05T19:06:12Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv777zVt','Bvd General George Magheru','bvd-general-george-magheru',44.4406728384126,26.09990201855037,'Mi-ar plăcea ca acest bulevard să nu mai fie o "autostradă" pentru şoferii Bucureştiului. Reducerea numărului de benzi auto şi amenajarea unor piste pentru bicilete (ideal separate de carosabil de un spațiu verde/copaci) ar schimba în bine aspectul zonei.','2025-08-05T18:15:04Z','2025-08-05T19:06:27Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv777k2d','Gradini urbane','gradini-urbane',44.41290746538075,26.034872531890873,'Aici este un spatiu gol imens, din povestile din cartier am inteles ca este al Armatei. Inteleg ca nu se pot da autorizatii pt a construi un parc permanent dar niste gradini urbane se pot face.  Sa pot face parcelari de cativa metrii patrati, pe care locuitori sa le ia in grija pe termen scurt 1 an. Modelul asta se practica in alte tari. De exemplu in Viena in cartierul Seestadt locuitorii au putut lua in grija mici gradini pt un an, la final de an predau gradina goala. Au facut asta pe o parcelare pt 4 ani, iar acum s-a inchis parcelarea respetiva pt ca se doreste sa se construiasca ceva. Pe acelasi model cred ca se poate face si la noi. In DL Taberei sunt multi oameni pasionati de gradinarit si asta se vede mergand printre blocuri. Asa ar putea sa aiba o mica gradina a lor si spatiul ala nu ar mai fi un camp urat. ','2025-08-05T18:10:11Z','2025-08-05T19:06:54Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv777cTZ','Casa Radio','casa-radio',44.43692059342809,26.07479094326816,'Această clădire abandonată ocupă un teren imens, care ar putea fi transformat într-un parc/spațiu comunitar. Având în vedere proximitatea față de universități şi cămine studențeşti, ar fi o zonă plină de tineret unde s-ar putea desfăşura şi evenimente culturale în aer liber.','2025-08-05T18:07:03Z','2025-08-05T19:07:06Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv776GVN','Un colt de cartier','un-colt-de-cartier',44.4313665707619,26.14209651947022,'Este o strada care se infunda aici care nu are legatura oficial cu spatele blocurilor, dar pe care unele masini o folosesc. Avand in vedere ca strada se infunda aici se poate face usor o mica piateta. Arbori exista deja, cateva bancute si interzis accesul cu masina celor care nu sunt riverani. In tp zilei parcheaza multe masini care vin la Registrul Comertului. ','2025-08-05T17:53:02Z','2025-08-05T19:07:23Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDxADMlP','Piațeta verde','piaeta-verde',44.431274250550366,26.079045197720074,'Micile intersecții din Cotroceni, piatele, pot fi transformate ușor în zone de socializare publica, de odihna intr o zona de promenadă, spatii publice prietenoase cu pietonii și natura, prin montarea de mobilier urban, băncuțe și jardiniere stradale. Acum sunt parcări ilegale, periculoase pentru pietoni, pentru copii care nu se vad din cauza mașinilor parcate.','2025-08-06T04:13:01Z','2025-08-06T05:33:20Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDxA3uqZ','Piața Floreasca','piaa-floreasca',44.46051073584546,26.09986782073975,'Interzisă circulația mașinilor și transformată în zona pietonală ','2025-08-06T00:12:40Z','2025-08-06T05:33:47Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDx9qbsF','Fabrica de bere Bragadiru','fabrica-de-bere-bragadiru',44.41935233994157,26.085727214813236,'Cladire mare a Bucurestiului vechi care ar schimba fata bulevardului si extinde zona turistic interesanta a orasului in partea de sud, impreuna cu cartierele de case istorice si parcul Carol.','2025-08-05T20:43:11Z','2025-08-06T05:33:57Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv77F9Un','Palatul Bragadiru','palatul-bragadiru',44.42158220841242,26.086574792861942,'Zona din fata superbului Palat Bragadiru arata deplorabil, cu masini parcate pe pamant si cu zero atractivitate pentru pietoni. Palatul poate fi pus in evidenta mult mai bine prin amenajarea din jurul sau cu o piateta mare care sa il favorizeze.','2025-08-05T20:41:45Z','2025-08-06T05:34:09Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDx9qIKn','Parc Ponton Floreasca','parc-ponton-floreasca',44.469071224701096,26.102957725524902,'Parcul este cu mult sub ce a fost promis sa fie, din pacate executia a fost o bataie de joc in stil tipic romanesc. Zona are in continuare potențial pentru o amenajare frumoasă si extindere de-a lungul malului lacului Floreasca inspre parcul Bordei.','2025-08-05T20:40:22Z','2025-08-06T05:35:02Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv77EMLz','Remanajare Piata Revolutiei','remanajare-piata-revolutiei',44.43878994704683,26.097475290298465,'Daca are loc remanajarea Pietei Revolutiei trebuie facuta respectand arhitectura zonei. Mobilierul stradal trebuie sa fie in armonie cu cladirile zonei. Trebuie gasita si o solutie pentru cei ce locuiesc in zona pentru a nu ramane totusi fara loc de parcare. Pentru minister s-ar putea construi o parcare subterana ','2025-08-05T20:19:19Z','2025-08-06T05:35:22Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k6wzKL','Complex Sportiv si Cultural','complex-sportiv-si-cultural',44.43833032265205,26.072273254394535,'Datorita proximitatii de Universitatea Nationala de Educatie Fizica si Sport, zonei ii poate fi redata functia din interbelic, cand aici se afla un stadion. Ar putea fi creat un complex sportiv modern dar cu arhitectura potrivita zonei, impreuna cu spatii verzi si locatii pentru evenimente culturale','2025-08-05T19:59:49Z','2025-08-06T05:35:34Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDx9pLa5','Pantelimon 89','pantelimon-89',44.44525541991253,26.136334726028338,'Toata zona este uitata in secolul trecut. Toate asa-zisele modernizari facute aici (ciment in diverse configuratii) n-au nicio legatura cu tendintele contemporane in urbanism.','2025-08-05T20:18:18Z','2025-08-06T05:35:46Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDx9o6V7','Refacerea orasului pierdut','refacerea-orasului-pierdut',44.43010243440225,26.091048717498783,'Reconstructia in zona Izvor, a noii cladiri a Academiei Romane, zona Unirii si Palatului Parlamentului pe cat se poate a strazilor si imobilelor demolate in perioada comunista, pastrand cat mai mult spatiu verde cu putina. Chiar posibila demolare si reconstruire a unor cladiri din anii ''80 pentru redarea arhitecturii interbelice a Micului Paris','2025-08-05T19:56:56Z','2025-08-06T05:36:00Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDx9nwnZ','Reamenajare zonei de est a sectorului 6','reamenajare-zonei-de-est-a-sectorului-6',44.43048755444696,26.060771942138675,replace('Un proiect ambitios care ar propune in prima parte reamenajarea intersectiei de la panduri, crearea unui parc in spatiile verzi disponibile si conectarea acestora cu cele existente si cu campusurile din zona- de la unibuc si cel de la leu, dar si reamenajarea strazii nicolae paulescu(din spatele campusului unibuc) pentru conectarea cu mica padure urbana de pe strada dr dumitru bagdasar. ar putea fi amenajata si piata eroilor, pentru a permite un acces facil in parcul romniceanu. \nastfel, am obtine o intersectie mai prietenoasa cu pietoni, un oras mai verde si o strada pietonala\n\nin faza a doua, zona mentionata anterior se poate conecta cu parcul linei(prin continuarea caii ferate), dar si cu campusul politehnica, parcul grozavesti, gradina botanica, printr-o promenada pe splaiul independentei, pe dambovita.','\n',char(10)),'2025-08-05T19:53:47Z','2025-08-06T05:36:18Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDx9nY8d','Teren fostul turn de lifturi','teren-fostul-turn-de-lifturi',44.45200188244312,26.059581041336063,replace('Ar putea fi un parc mare. Cat mai multi copaci si natura, minimal amenajat (in loc de asflat nisip sau lietris tasat). Ar ajuta mult la captarea poluarii traficului intens de pe Podul Grant, calea Plevnei/Giulesti si ar actiona si ca un paravan fata de caile ferate.\nAm inteles ca terenul a fost cumparat si va fi construit un complex rezidential. Se construiesc foarte multe cladiri inalte in zona, dar nu sunt pastrate sau introduse spatii verzi. ','\n',char(10)),'2025-08-05T19:44:43Z','2025-08-06T05:36:32Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv77Bqoh','Intersectia Lujerlui','intersectia-lujerlui',44.434515300634274,26.035065650939945,replace('Militari fiind unul din cele mai aglomerate si poluate cartiere ar merita o reconfigurare urbana a celei mai mari intersectii . Astfel s-ar putea\n reda cat mai mult spatiu inapoi rezidentilor sau a celor in tranzit pentru a petrece timpul in spatii relaxante , sigure , verzi (preferabil umbrite natural) din cuantumul parcarilor sau a zonelor prost amenajate','\n',char(10)),'2025-08-05T19:21:19Z','2025-08-06T05:36:52Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k7bntB','Un parc','un-parc',44.407082710908114,26.19601964950562,'Un parc în zonă este absolut necesar','2025-08-06T10:30:28Z','2025-08-06T12:12:50Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDxAIb3K','Pallady-Policolor ','pallady-policolor-',44.418335101012424,26.197858303785328,'Parc intr-un cartier supraaglomerat.','2025-08-06T06:45:17Z','2025-08-06T12:13:08Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDxAmwZl','Parcul Alba Iulia','parcul-alba-iulia',44.425520668658095,26.129136085510257,'În locul parcării ar putea fi reconfigurată intersecția, realizându-se astfel un parc, eventual construind și o parcare subterană.','2025-08-06T10:12:21Z','2025-08-06T12:13:46Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDxAM2qH','Gradina comunitatii','gradina-comunitatii',44.43330486007521,26.164873838424686,'Gradinile blocurilor G6 si G5 sunt unite si ingradite, blocand accesul cetatenilor atat pentru acces la gradina si relaxare, cat si pentru tranzit (din Intrarea Barsei, bloc G7 spre Intrarea Barsei bloc G3/G4). Propun deschiderea acestei zone prin crearea unui scuar sau al unui parc (in niciun caz nu trebuie sa se faca acces auto, ci sa ramana spatiu verde)','2025-08-06T07:49:26Z','2025-08-06T12:14:04Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k7aom9','Amenajarea malului Dâmboviței','amenajarea-malului-dmboviei',44.425704559150766,26.10879421234131,'Faleză pietonală, înverzită de copaci, cu spațiu pietonal, mobilier urban și pop-up-uri pentru diverse evenimente.','2025-08-06T10:14:07Z','2025-08-06T12:14:16Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv77lFAX','Baba novac','baba-novac',44.42435601543761,26.13735437393189,'Mai putine benzi, mai putin zgomot, sa nu ia ani sa traversezi speriat de cine o sa te calce azi','2025-08-06T08:11:11Z','2025-08-06T12:14:26Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv77ksGf','Zona Pietonala','zona-pietonala',44.43268430804208,26.106455326080326,'Zona dintre Bd I.C. Bratianu, Corneliu Coposu, Hristo Botev si Carol I ar trebui sa fie pietonala la fel ca actualul centru vechi si reabilitarea cladirilor abandonate','2025-08-06T07:59:40Z','2025-08-06T12:13:29Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k7M67J','Foișorul de foc','foiorul-de-foc',44.440682029393905,26.120692491531376,'Scuar pirtonal cu giratoriu în jurul său de 1-2 benzi pe sens cu reducere de viteza. Copaci pe margine, dar nu lângă foișor ca sa se vadă. Tramvai separat de trafic','2025-08-06T08:06:44Z','2025-08-06T12:14:36Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('MZFnxNx2eBhnA3GVBikSA5','Piste de Biciclete','piste-de-biciclete',44.43539630173174,26.10226035118103,'Ar fi foarte folositoare piste de biciclete care le ar continua pe cele existente (din pacate pe trotuar) de pe Bd Regina Elisabeta si sa traverseze intersectia de la Universitate si sa continue inspre Piata Iancului','2025-08-06T12:27:07Z','2025-08-06T14:57:56Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8DVLEi','Mai putine benzi','mai-putine-benzi',44.442934063734455,26.081038713455204,'Spatiul din interiorul rondului ar trebuie sa fie folosit doar de transportul in comun si eliminarea benzilor auto pentru spatii verzi','2025-08-06T14:35:18Z','2025-08-06T15:00:01Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8DT5Uc','Gura Calitei','gura-calitei',44.41347458153626,26.196448802948,'Avem nevoie de un parc adevarat, zona nu are parc decat departe care e inaccesibil de mers pe jos. Foarte mult praf, multe masini, zero transport in comun.','2025-08-06T13:51:23Z','2025-08-06T15:00:18Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('MZFnxNx2eBhnA3GVBirvIv','Perdea de arbori pe Victor Brauner','perdea-de-arbori-pe-victor-brauner',44.40971651788762,26.19445323944092,'Pe ceea ce acum este o bandă de spațiu verde neamenajat și care devine câteodată o pajiște îngustă plină de flori și fluturi, mi-aș dori să existe și un perete vegetal înalt care să separe zona rezidențială de cea industrială. ','2025-08-06T13:45:41Z','2025-08-06T15:00:46Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('MZFnxNx2eBhnA3GVBiqTOj','Scoalei','scoalei',44.440996093813546,26.103193759918216,'Desi este o strada in proximitatea unei gradinite si a unei scoli, cu mult trafic pietonal, nu este deloc disponibila pietonilor, ci o vesnica parcare. ','2025-08-06T13:15:08Z','2025-08-06T15:01:02Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8DL8VA','Conexiune metrou - cale ferata','conexiune-metrou-cale-ferata',44.48652521843587,26.120166778564457,'Tinand cont ca metroul si calea ferata au acelasi ecartament (si sunt deja legate la Tudor Arghezi), de ce nu mai putem adauga o conexiune la Gara de Nord astfel incit metroul sa circule si pe calea ferata pentru a deservi partea de Nord a capitalei cu statii mai dese intre Gara de Nord - Voluntari - Obor? Berlin S-Bahn vibes','2025-08-06T12:43:41Z','2025-08-06T15:01:26Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('MZFnxNx2eBhnA3GVBilTvd','Shopping cu transport alternativ','shopping-cu-transport-alternativ',44.503300626648304,26.081027984619144,'Daca imi place sa merg cu bicicleta, as dori sa pot sa ajung printr-un drum direct, separat de masini, pina la Baneasa Shopping City. Si, de ce nu, poate si mai departe?','2025-08-06T12:37:56Z','2025-08-06T15:01:49Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv77kSuf','Regenerare urbana','regenerare-urbana',44.434476995937445,26.169197559356693,'In aceasta zona se afla o cladire abandonata de cel putin 20-30 ani. Propun demolarea acestei constructii si crearea unui parc','2025-08-06T07:46:19Z','2025-08-06T15:02:06Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv77kLLb','Parcare verde','parcare-verde1',44.43400201561075,26.16567850112915,'In aceasta locatie sunt trasate parcari. Fiind la intersectia a 3 cai de acces, are o forma de triunghi. Aici ar putea sa fie plantati niste copaci si creat un mic scuar, in jurul caruia sa fie amplasate parcarile.','2025-08-06T07:41:35Z','2025-08-06T15:02:48Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k7Lk0f','Parcare verde','parcare-verde',44.43278390325674,26.166890859603882,'In aceasta zona sunt trasate parcari pe marginea celor doua cai de acces, iar acolo unde se unesc este o ghena. Intre parcarile de pe partea stanga si cele de pe dreapta este un spatiu care, in loc sa fie verde si prietenos cu pietonii, este folosit de masini care parcheaza ilegal. Propun transformarea acestei zone intr-un scuar, care sa aiba parcarile de o parte si de alta a acestuia.','2025-08-06T07:43:35Z','2025-08-06T15:03:07Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDxALgk5','Parcul Toboganul de piatra','parcul-toboganul-de-piatra',44.42986492694422,26.157975196838382,'Aici a fost candva un parc, retrocedat ILEGAL dupa modelul IOR. Locatia, emblematica pentru cartier datorita fostului tobogan de piatra a devenit o parcare parjolita de soare, inconjurata de un spatiu insalubru, neingrijit si plin de boscheti. Aici, ca si in IOR este obligatoriu ca zona sa redevina parc, sa fie amenajata ca o oaza de natura si liniste si sa fie adusa la starea de dinainte de retrocedarea ilegala. ','2025-08-06T07:38:01Z','2025-08-06T15:03:31Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('o47Zn7oFdWze1BV8k7LW1Z','Parcul IOR','parcul-ior',44.4270377479225,26.16125822067261,'Este absolut obligatoriu ca aceasta zona retrocedata ILEGAL sa revina la statutul de parc, sa fie adusa la starea de dinainte de crima defrisarii si sa fie amenajat din nou ca o oaza de natura in orasul acesta sufocat de betoane si masini.','2025-08-06T07:33:47Z','2025-08-06T15:04:10Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('ZZY8An29bJrWJ3gv77jIBj','Intrare Spital Fundeni','intrare-spital-fundeni',44.46646392160016,26.156505115730415,'Aranjamente cu flori, copaci, bancute de asteptare, un mic loc de joaca penfru copii','2025-08-06T07:19:03Z','2025-08-06T15:04:24Z',NULL,NULL,NULL,NULL,NULL);
