INSERT INTO geopoints VALUES('GOBSY6qrvDx36ZvDxAJ8Ky','Parc/ loc de joaca','parc-loc-de-joaca',44.41658319447897,26.204316526357015,'As dori un parc cu multa verdeata si locuri de joaca pentru copii care sa fie deschis tuturor oamenilor care locuiesc in zona','2025-08-06T06:54:05Z','2025-08-06T15:04:55Z',NULL,NULL,NULL,NULL,NULL);
