INSERT INTO geopoints VALUES('MZFnxNx2eBhnA3GVBjRJTd','Parc','parceee',44.43815647577538,26.073852923571078,'Se poate amenaja un parc, fiind zonă centrală și  nevoia de spațiu verde este imensă acolo!','2025-08-06T21:46:13Z','2025-08-07T04:52:20Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb59jPA','Parklet la umbra unui frasin stingher','parklet-la-umbra-unui-frasin-stingher',44.41282316386111,26.19174957275391,'Un frasin aflat într-un colț de parcare a devenit loc de întâlnire pentru oameni. E și motivul pentru care locul de parcarea de lângă el este la mare căutare vara - e singurul umbrit cât de cât. Mi-aș dori să scoatem de pe bietul arbore anunțurile cu „vând teren” și să-l îngrijim în timp ce ne și bucurăm de umbra lui într-un parklet vesel și verde.','2025-08-06T20:47:19Z','2025-08-07T04:52:35Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('MZFnxNx2eBhnA3GVBjQGkj','Treceri de Pietono','treceri-de-pietono',44.428424538459446,26.15504622459412,'Trecerile de Pietoni din aceasta intersectie pot fi ridicate deoarece nu sunt semafoare, iar intersectia poate fi transformat in sens giratoriu ca masinile sa incetineasca si mai mult','2025-08-06T20:35:28Z','2025-08-07T04:52:56Z',NULL,NULL,NULL,NULL,NULL);
