INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Dhox0','Zona verde/ agrement','zona-verde-agrement',44.413416828124134,26.195543755839743,'In zona Gurilor necesitam un loc cu verdeata, alei pietonale si locuri de joaca pentru copii','2025-08-06T16:31:40Z','2025-08-07T04:53:19Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb4ZMPF','Piața Gării de Nord','piaa-grii-de-nord',44.446840510190746,26.075459491284025,'Mi-aș dori ca zona din jurul Monumentului Eroilor Ceferiști să fie pietonală în loc de parcarea din prezent. Aici pot fi montate bănci, plantați copaci și să fie pusă în valoare o locomotivă veche.','2025-08-06T16:11:25Z','2025-08-07T04:53:31Z',NULL,NULL,NULL,NULL,NULL);
