INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Ddalq','Parcare obor și căi acces Obor','parcare-obor-i-ci-acces-obor',44.450494879617516,26.12898774491085,replace('In principal desființare.\nÎn subsidiar pe toate fâșiile de pământ plantați arbori, arbuști, tufe, tufișuri și plante perene, mature, diverse și rezistente la secetă cu program de udare până se prind.','\n',char(10)),'2025-08-06T15:50:42Z','2025-08-07T04:54:11Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8DaFuY','Piața Valter Mărăcineanu','piaa-valter-mrcineanu',44.43738808133972,26.093291044235233,'Mi-aș dori ca în acest loc să fie organizate expoziții de fotografie în aer liber. Pe inelul exterior al pieței pot fi puse mai multe bănci verzi și un chioșc în stilul celor din Parcul Cișmigiu. Tot aici ar putea fi montată o stație automatizată/simplă pentru cei care vor să închirieze biciclete cu care să se plimbe prin Parcul Cișmigiu. ','2025-08-06T15:41:29Z','2025-08-07T04:54:25Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8EPrww','Extindere spațiu verde din intersecție ','extindere-spaiu-verde-din-intersecie-',44.42381965417737,26.176943778991703,'Intersecția Liviu Rebreanu cu 1 Decembrie are un scuar cu puțină iarbă. Acesta poate fi extins de 3 ori față de mărimea actuală și pot fi plantați copaci, diminuând suprafața asfaltată și astfel reducând poluarea și căldura din intersecția respectivă. ','2025-08-07T05:35:49Z','2025-08-07T11:52:47Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb5Vonp','Plantare copaci pe Liviu Rebreanu ','plantare-copaci-pe-liviu-rebreanu-',44.423605108295384,26.175903081893924,'Transformarea tufișurilor în copaci pentru a reduce căldura din zona și a preveni parcările ilegale care deteriorează spațiul verde actual. Acesta se întinde de la Mega Image Agârbiceanu până la Gyros de pe Liviu Rebreanu','2025-08-07T05:40:10Z','2025-08-07T11:53:01Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Ew9zm','Linia de Tramvai 1 Decembrie','linia-de-tramvai-1-decembrie',44.41485403030773,26.17398262023926,'Linia de tramvai de pe Bd 1 Decembrie 1918 ar putea fi separata complet de traficul auto','2025-08-07T12:07:42Z','2025-08-08T07:45:30Z',NULL,NULL,NULL,NULL,NULL);
