INSERT INTO geopoints VALUES('MZFnxNx2eBhnA3GVBk4ng1','Zonă pietonală+pistă biciclete ','zon-pietonalpist-biciclete-',44.42880109772405,26.07017350875533,replace('E o zonă simbolică a istoriei recente a României. Traficul rutier nu își are locul aici. \nPropun zonă pietonală ,cel mult trafic biciclete ','\n',char(10)),'2025-08-07T12:11:57Z','2025-08-08T07:46:01Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb68Ugw','Umbră/copaci','umbrcopaci',44.41575313132486,26.04866981506348,'Umbra lipsește cu desăvârșire, este imposibil de mers vara pe stradă în lipsa copacilor ','2025-08-07T12:14:01Z','2025-08-08T07:46:13Z',NULL,NULL,NULL,NULL,NULL);
