INSERT INTO geopoints VALUES('MZFnxNx2eBhnA3GVBkMKxd','Spațiu verde în zona Gurilor','spaiu-verde-n-zona-gurilor',44.41191116692573,26.19168519973755,'Spațiu dedicat copiilor, oamenilor, câinilor, spațiu deschis, verde, copaci și umbră ','2025-08-07T13:26:37Z','2025-08-08T07:46:34Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('Y36qV9ZHzvlDm0JZd3ezNf','Parc','parc2233',44.412072727941016,26.193983454222874,'Un parc pt socializare in locul prafului de sticla de la fabrica existenta','2025-08-07T18:38:38Z','2025-08-08T07:46:49Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb7OdxO','Drumul Gura Racului-Drumul Gura Carlitei','drumul-gura-racului-drumul-gura-carlitei',44.411779372175324,26.202553510665897,'Ar putea fi amenajat un parc care sa integreze și locuri de joaca, dar și o zonă de agrement.Datorita faptului că încă nu s a construit nimic pe aceea parcela, este înconjurată de multe complexe rezidențiale, deservind un număr mare de locuitori si cel mai apropiat parc este parcul teilor, la 2 kilometrii de mers pe jos, cred că acest loc ar fi o alegere bună. Un parc cred că ar ajuta și cu temperaturile foarte mari, in aceea zona fiind foarte putini copaci/umbră.','2025-08-07T18:47:25Z','2025-08-08T07:47:01Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('Y36qV9ZHzvlDm0JZd3qMd7','Drumul Gura Racului','drumul-gura-racului',44.41184985569721,26.202306747436527,'Mi aș dori să văd în acest loc un parc cu multa verdeață și alei pentru plimbare, ar prinde bine printre toate blocurile din jur :)','2025-08-08T09:08:39Z','2025-08-08T11:21:07Z',NULL,NULL,NULL,NULL,NULL);
