INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb8E8dC','Str drumul gura putnei','str-drumul-gura-putnei',44.41250168255233,26.191882371731488,'Spațiu verde cu alei, băncuțe, multa umbra și locuri de joaca pentru cei mici','2025-08-08T09:26:05Z','2025-08-08T12:26:54Z',NULL,NULL,NULL,NULL,NULL);
