INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8GZSZW','Parc','parcewew',44.41664726506446,26.20310068130493,'Sa fie plantati copaci si amenjat ca un spatiu verde de relaxare cu cateva bancute, multa umbra. Ce ne dorim e sa avem o zona verde apropiata unde sa putem iesi pentru o plimbare scurta, fara prea mult ciment, amenajata astfel incat sa asigure liniste si oxigen.','2025-08-08T09:32:25Z','2025-08-08T12:28:13Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb8EZhG','Platforma industriala, spațiu verde','platforma-industriala-spaiu-verde',44.40539458774225,26.196920871734623,'Să se faca un parc ','2025-08-08T09:35:17Z','2025-08-08T12:29:09Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Gad62','Oaza de pomi','oaza-de-pomi',44.4189998443577,26.201190948486328,'Este o zona in care se pot planta copaci si sa se faca umbra atat blocurilor cat si sa eliminam spatiul care acum e acoperit de balarii si ambrozie. Se poate face si un mic parculet','2025-08-08T09:50:20Z','2025-08-08T12:29:25Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8GbEOA','Parc/loc de joaca','parcloc-de-joaca',44.41397460106374,26.19596387064721,'Multi copii au nevoie de un spatiu de joaca in proximitatea casei, unde sa fie in siguranta, nu sa mearga zeci de minute pana la cel mai apropiat parc.','2025-08-08T10:02:31Z','2025-08-08T12:29:57Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Gbx2y','Parc in zona Theodor Pallady','parc-in-zona-theodor-pallady',44.41139768340185,26.19612693786621,'Este un teren pustiu destul de mare, mi-as dori sa vad un parc.','2025-08-08T10:15:00Z','2025-08-08T12:30:11Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb8FoFY','Parc + trotuare + iluminat','parc-trotuare-iluminat',44.41854772734585,26.199538707733158,'Amenajarea unui parc+finalizare traseu trotuar pana in capatul strazii Gura Calitei+ iluminat!','2025-08-08T09:52:12Z','2025-08-08T12:29:40Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8GlyLY','Parc pentru cartierul Pallady','parc-pentru-cartierul-pallady',44.41128708134677,26.193040721005822,'Pentru ca Primari Sectorului 3 nu tine cont nici de petiții, nici de sesizări, nu ne rămâne decât sa apelam la voi. Ne dorim un parc zona Pallady, fost Policolor. Cel mai apropiat parc este la marginea cartierului unde accesul este foarte dificil pentru ca nu avem trotuare. Ne-am saturat de praful de la firma care cică reciclează sticla și vrem un spațiu verde dedicat pentru relexare atât pentru cei mici, cât și pentru adulți. ','2025-08-08T10:51:58Z','2025-08-08T12:31:21Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('Y36qV9ZHzvlDm0JZd3vXeT','Necesitatea unor spatii verzi in zona Drumul Gura Putnei-Drumul Gura Crivatului','necesitatea-unor-spatii-verzi-in-zona-drumul-gura-putnei-drumul-gura-crivatului',44.41024041296011,26.19295120239258,'Avem nevoie de mai multe zone verzi in acest cartier, parcuri, locuri de joaca.','2025-08-08T11:06:22Z','2025-08-08T12:32:01Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb8YQeI','Parc in zona Drumul Gura Putnei-Drumul Gura Crivatului','parc-in-zona-drumul-gura-putnei-drumul-gura-crivatului',44.413083731801905,26.192167997360233,'Avem nevoie de spatii verzi, locuri de joaca, spatii amenajate pentru animalele de companie.','2025-08-08T11:07:39Z','2025-08-08T12:32:20Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb8Yqif','Parc','parce',44.41327635477877,26.195868199776463,'Este necesar un parc in zona Pallady. ','2025-08-08T11:11:37Z','2025-08-08T12:32:56Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8GnEk8','parc sau promenada','parc-sau-promenada',44.41197856132637,26.193798780441288,'e un spațiu nefolosit, plin de buruieni si lighioane, macar de ar fi curatat. Daca e private sa se incerce expropierea sau sa fie proprietarul spatiului amendat și obligat sa îl curete. ','2025-08-08T11:12:49Z','2025-08-08T12:33:44Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8GnIC6','Parc pentru comunitatea Titanului nou','parc-pentru-comunitatea-titanului-nou',44.40919324456313,26.2069845199585,replace('Titanul nou/zona Pallady are multe locuințe si puține parcuri. \nSectorul 3 era cel mai verde al Bucureștiului. As vrea sa rămână la fel.','\n',char(10)),'2025-08-08T11:13:59Z','2025-08-08T12:33:58Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb8Z5Nc','Teren','teren',44.41232381308925,26.191998243684797,replace('Parc, spatiu verde, loc de relaxare pentru locuitori sau de ce nu, o scoala\n','\n',char(10)),'2025-08-08T11:14:56Z','2025-08-08T12:34:14Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('Y36qV9ZHzvlDm0JZd3vr4R','Drumul Gura Gârliței la intersecție cu Drumul Gura Racului','drumul-gura-grliei-la-intersecie-cu-drumul-gura-racului',44.41200417826848,26.202905456868077,'Aș dori aici un spațiu verde, este loc, și nevoie de el cu atât mai multă, încât multe complexe rezidențiale îl înconjoară... Copaci, băncuțe la umbră, poate o masă de șah, un foișor...','2025-08-08T11:25:26Z','2025-08-08T12:35:49Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('Y36qV9ZHzvlDm0JZd3vrPx','Parcul Gurilor','parcul-gurilor',44.41618681940561,26.20477270334959,replace('Sectorul 3 a fost cel mai verde din București. \nÎmi doresc sa rămână la fel.','\n',char(10)),'2025-08-08T11:25:54Z','2025-08-08T12:36:13Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8GoLrs','Spatiu verde Victor Brauner','spatiu-verde-victor-brauner',44.40976523568381,26.19198560714722,'Fabrica de sticla ar trebui mutata in alta locatie si in locul ei amenajat un parc, sau macar pe o parte din spatiu','2025-08-08T11:29:07Z','2025-08-08T12:36:41Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb8ZwiO','Parc în loc de spălătorie','parc-n-loc-de-spltorie',44.413552250208525,26.194257233601444,replace('Aș dori să văd un parc lângă biserică, s-ar potrivi atât de bine pentru oamenii înghesuiți în această zonă. În plus, spălătoria în sine generează poluare fonică și ar putea fi relocată mai departe de aglomerația de locatari.\nAr fi un vis împlinit înlocuirea spălătoriei auto cu un parc, ba chiar aș dona pentru înfăptuirea ei.','\n',char(10)),'2025-08-08T11:27:53Z','2025-08-08T12:36:30Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8GoMEE','Parc','parceeeee',44.41385010136956,26.204892396926883,'În zona gurilor este imperios necesar un parc, o zonă de agrement. Aceasta lipsește cu desăvârșire iar copiii au nevoie de acest loc. ','2025-08-08T11:29:15Z','2025-08-08T12:39:09Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb8a4bp','Spălătorie auto transformată în parc','spltorie-auto-transformat-n-parc',44.41375086801788,26.196758108239585,'S-ar putea înlocui spălătoria de lângă biserică în parc, poate chiar extins și în zonele industriale de lângă (care par abandonate?). Sunt extrem de multe complexe rezidențiale, literalmente zeci de mii de cetățeni ce ar beneficia.','2025-08-08T11:30:14Z','2025-08-08T12:40:24Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb8adlf','Spațiu de relaxare','spaiu-de-relaxare',44.411880511319495,26.193069219589233,'Zona are nevoie urgentă de un loc de relaxare/socializare. Dezvoltarea haotică, fără a ține cont de normele în vigoare, a dus la apariția unui cartier plin de blocuri și betoane fără spații verzi. Drept urmare e nevoie de un parc.','2025-08-08T11:38:20Z','2025-08-08T12:40:43Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCMqRH','Intersectia de la IOR-Park Lake nu prezint asiguranta','intersectia-de-la-ior-park-lake-nu-prezint-asiguranta',44.423480520452486,26.150701045989994,replace('Pentru masinile care fac stanga spre Titan, trecerea de pietoni este verde, insa semnalul se face in scurt timp rosu, nu e deloc intiutiv, iar vizibilitatea acestuia e scazuta. Este complicat pentru soferul mediu sa anticipeze iar prudenta in trafic nu este punctul forte. \nSincronizarea semafoarelor este foarte alambicata si ar fi benefice mai multe treceri de pietoni sau macar una in fata mall-ului avand in vedere traficul mare de pietoni si faptul ca distanta dintre intersectia aceasta si cea de la Ramnicul Sarat este mare','\n',char(10)),'2025-08-10T05:33:13Z','2025-08-10T06:37:42Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gbgb6','O trecere de pietoni foarte periculoasa','o-trecere-de-pietoni-foarte-periculoasa',44.42804034580883,26.148319244384766,'Trecere nesemaforizata, vizibilitate scazuta datorita parcarilor, semnalizare minimala, masinile merg cu viteza. Ar fi minunata instalarea unor limitatoare de viteza, ne-am simti in siguranta cand trecem, avand in vedere ca soferii de multe ori sunt mai interesati de bunastarea masinii lor decat de pietonii care vor sa traverseze.','2025-08-10T05:27:40Z','2025-08-10T06:37:53Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBatwC','Conacul Cantacuzino','conacul-cantacuzino',44.410719850147565,26.16043474865296,'Tot ansamblul conacului ar putea fi retrocedat statului si transformat într-un veritabil loc cultural cu muzee, parc, etc, acum locul se degradeaza constant si isi pierde pe zi ce trece valoarea culturală.','2025-08-10T04:05:25Z','2025-08-10T06:38:15Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBZrr8','Mihai Bravu- Baba Novac','mihai-bravu-baba-novac',44.42530585321269,26.137719154357914,'Șoseaua Mihai Bravu, pe sensul de la Baba Novac până la pasaj, nu are nevoie de 4 benzi care devin 3 care devin 2. Pot fi doar 2 benzi de circulație, lărgit trotuar, bandă de bicicletă, parcare cu plată.','2025-08-10T03:23:24Z','2025-08-10T06:38:45Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JdY0A','Parcarea din fata ateneului ','parcarea-din-fata-ateneului-',44.440638257381,26.09612107639769,'Extinderea zonei verzi din fata ateneului, scoaterea parcărilor de acolo','2025-08-10T04:56:45Z','2025-08-10T06:38:02Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gPRCC','Reconfigurare benzi Baba Novac','reconfigurare-benzi-baba-novac',44.42440938197224,26.137729883193973,'La virajul la dreapta de pe Baba Novac pe Mihai Bravu sunt 3 benzi de circulație. Prima dreapta și înainte, 2 care fac rondul. Fluxul de mașini necesită banda 1 obligat dreapta, banda 2 dreapta și înainte, banda 3 rondul.','2025-08-10T03:27:35Z','2025-08-10T06:38:28Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JE03M','Extindere parc traian','extindere-parc-traian',44.43875136421883,26.120628118515018,'Este un spațiu mare și inutil de asfalt. Spatiul verde de lângă ar avea o continuare foarte frumoasă și aici, separat numai de 2 benzi de circulație (pentru tramvai, autobuze și mașini). Câteva băncuțe, copaci, piatră pe jos, măsuțe. Ar fi 100% folosite inclusiv în timpul orelor de muncă pentru că mereu văd elevi prin zonă care nu au unde să stea puțin să socializeze / cu cafea / niște mici de la magazinul de lângă.','2025-08-10T03:07:45Z','2025-08-10T06:40:00Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBRaCv','(Fostul) Parcul Constantin Brancusi','fostul-parcul-constantin-brancusi',44.429435033653284,26.164816564962234,'Parcul a fost distrus in urma cu 3 ani, acum parcela ramane neutilizata plina de buruieni si gunoaie. Imi doresc ca spatiul sa se intoarca la scopul lui original: un spatiu pentru oameni, cu zone unde se poate sta si socializa si locuri amenajate pentru copilasii cartierului.','2025-08-09T22:05:13Z','2025-08-10T06:40:14Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JEC6e','Îngustare strada Traian','ngustare-strada-traian',44.43941018834974,26.120574474334717,'Momentan are 4 benzi. 1 pe sens Foișor- Pache (comună cu tramvai), 3 invers (1 de tramvai, 1 de auto, 1 de staționare interzisă). Doar 2 benzi în total sunt suficiente pentru transport public + auto). Cele 2 benzi in plus pot fi convertite în parcare cu plată, benzi de biciclete (cred că face parte din planul Velo), largit trotuarul, copaci pentru umbră.','2025-08-10T03:13:40Z','2025-08-10T06:39:45Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J86Ba','Spații verzi','spaii-verzi',44.432523423106,26.1380410194397,'Trotuar - asfalt de 10 m lățime, între blocuri și intrarea în pasaj. Se poate amenaja o fâșie de spațiu verde de 4-5m ca o barieră verde între praful, zgomotul făcut de mașinile care intră în pasaj. Plus ca ar fi umbră pentru pietoni, și se pot amenaja cafenele/terase.','2025-08-09T21:49:43Z','2025-08-10T06:41:32Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gMucm','Parcul natural IOR','parcul-natural-ior',44.42535210186497,26.161193847656254,'Zona ar putea sa devina un parc natural, ca o rezervatie in miniatura unde animalele si pasarile sa-si gaseasca adapost. In afara de cateva alei, sa fie lasat cat mai natural. In mijloc, sa se faca o mica gradina comunitara, unde oamenii sa creasca legume si fructe. Cateva rate si gaini sa umble libere prin parc. Se mai pot face si niste santuri de irigatie, pentru mentinerea umiditatii solului.','2025-08-09T21:37:37Z','2025-08-10T06:41:59Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J7d22','Gara de Nord','gara-de-nord',44.44665143547358,26.075258830187526,'Mai mult spațiu pentru pietoni','2025-08-09T21:30:45Z','2025-08-10T06:42:10Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J7btm','Piata Unirii fara masini','piata-unirii-fara-masini',44.427803934607034,26.102657318115238,'Zona Unirii ar putea sa devina pietonala, un loc plin de verdeata si unde oamenii se pot conecta cu raul Dambovita. N-ar mai exista planseul si toata piata ar fi un sistem de iazuri si piscine naturale, unde s-ar putea practica sporturi de apa: inot, kayak, etc. Acest wetland ar proteja Bucurestiul de inundatii, absorbind apa in cazul ploilor mai puternice. Mai multe poduri mici din materiale naturale ar traversa raul, ca intr-o gradina japoneza. Aceasta zona verde ar continua pe tot traseul Dambovitei, cu piste de biciclete si de alergare. Raul ar deveni navigabil si barci mici ar asigura transportul in comun.','2025-08-09T21:26:37Z','2025-08-10T06:43:04Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBOwsx','Piața Romană','piaa-romanaaa',44.447016749037694,26.09660625457764,replace('Să se transforme dintr-una din cele mai gălăgioase și periculoase intersecții din București într-o piață mare și semi pietonală. Lascăr Catargiu și Dacia sunt două dintre cele mai frumoase bulevarde din București, ambele intersectându-se cu Piața Romană. Exact din mijlocul pieței, dacă privești în direcția celor două străzi, poți admira o grămadă de clădiri foarte impresionante arhitectural. \n     Așadar, aș lăsa doar câte o bandă de circulație pentru autobus și troleibus, și în rest totul făcut pietonal. Adus trotuarul la nivel cu carosabilul, făcut din cercul central, cel mic al pieței, o insulă verde cu un copac imens în mijloc, iar în rest zonă de promenadă cu piatră cubică, copaci de jur împrejur. Cam la atât mă pot gândi la ora asta. Mulțumesc că ați citit și salut cu drag inițiativa. Spor!','\n',char(10)),'2025-08-09T20:28:46Z','2025-08-10T06:43:26Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J5Xh2','Benzi dedicate autobuz','benzi-dedicate-autobuz',44.46696838960157,26.053133010864258,'Sunt masini parcate si abandonate pe prima banda in conditiile in care stationarea este interzisa. Acea banda poate fi transformata cu efort minim in banda speciala pentru  autobuz si troleibuz.','2025-08-09T20:08:36Z','2025-08-10T06:43:52Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J5RfO','Reconstructie Pod Constanta','reconstructie-pod-constanta',44.475462650293565,26.04664206504822,'Podul/Pasajul Constanta este complet depasit, este necesare reconstructia/largirea lui. Ca pieton, este aproape imposibil sa il traversezi, ai fie varianta subtraversarii pe un trotuar de 30-40cm latime cu masini care trec cu 60-80km/h pe langa tine, fie traversarea pe deasupra, trecand pe jos liniile de cale ferata.','2025-08-09T20:03:13Z','2025-08-10T06:44:24Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J5HMg','Parc in inima capitalei','parc-in-inima-capitalei',44.42501496682047,26.11604690551758,replace('Desi mai exista deja un pin adaugat aici, o sa mai adaug si eu unul pentru a sublinia nevoia acuta de a transforma acest spatiu intr-un parc verde. \nNu exista niciun motiv, cu exceptia birocratiei complicate, ca acest spatiu sa ramana nefolosit in continuare. Infrastructura din zona poate suporta fluxul de oameni pe care l-ar aduce un parc (existand numeroase legaturi STB in zona si mai mult decat suficiente baterii cu locuri de parcare ale CMPB) si terenul este inconjurat pe mare parte din perimetru de zone fara locuinte, ce nu ar suferi din cauza eventualei galagii sau zumzet al oamenilor ce ar veni acolo.\nMai mult, in acest loc inca se mai adapostesc pe timpul noptii diverse persoane fara adapost si consumatoare de droguri, iar inlocuirea acestui spatiu nefolosit cu unul mai populat de oameni i-ar descuraja sa mai faca acest lucru in acest spatiu, sporind siguranta zonei.\nSi in cele din urma, mai ales cu recenta desfiintare a parcului de la piata Unirii, locuritorii din zona au ramas fara un spatiu verde de relaxare sau unde sa poata practica sport.','\n',char(10)),'2025-08-09T19:56:36Z','2025-08-10T06:44:44Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBNjvN','Metrou Piața Unirii','metrou-piaa-unirii',44.42759265333827,26.104171138289257,'Ar fi genial la toate stațiile de metrou să existe “parcari” de biciclete. ','2025-08-09T19:51:24Z','2025-08-10T06:45:11Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBKlRO','Zambaccian colt cu Dorobanti','zambaccian-colt-cu-dorobanti',44.46071748874069,26.093698740005493,'Exista un scuar care ar putea fi inverzit sau valorificat in alt fel, nu lasat gol sau plin de masini.','2025-08-09T18:06:08Z','2025-08-10T06:46:31Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gLs5U','Reconfigurare benzi','reconfigurare-benzi',44.464494095669956,26.089675426483158,'Reconfigurare benzi pe Calea Dorobanti, transformarea a 2 benzi in benzi dedicate pentru autobuze, pe aceasta portiune autobuzul mai mult sta decat circula.','2025-08-09T19:49:35Z','2025-08-10T06:46:47Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J57N8','Malul Dambovitei pietonal','malul-dambovitei-pietonal',44.43213940453228,26.093516349792484,'Splaiul Independentei intre Parcul Izvor si Piata Unirii poate fi complet pietonalizat prin redirijarea traficului pe Bld Libertatii si Bld Unirii. Malul Dambovitei ar putea fi complet refacut dupa modelul altor capitale cum ar fi malul Senei in Paris.','2025-08-09T19:43:44Z','2025-08-10T06:47:01Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J4yic','transformare intersectie strada zizin','transformare-intersectie-strada-zizin',44.416593906376384,26.12434029579163,'Strada zizin x Str branduselor este o zonă foarte aglomerată unde șoferii nu respectă prioritatea pietonilor pe trecere. In această zonă se află 1 școală și o grădiniță','2025-08-09T19:37:22Z','2025-08-10T06:47:15Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J48x6','Pietonalizare','pietonalizare',44.43927254877011,26.098934412002563,'Pietonalizarea unor strazi intre Calea Victoriei si Bld Magheru. Cred ca sunt prea multe strazi cu trafic auto paralele, se mai poate renunta la cateva.','2025-08-09T19:05:28Z','2025-08-10T06:47:29Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J46aC','Parcare Pacii','parcare-pacii',44.43394838855712,25.99945664405823,'Eliminarea parcări pe bretea și înlocuit cu spațiu verde ce ar crea (mai ales prin alipirea cu parcul Păcii) un culoar verde continuu pe tronsonul de pe Iuliu Maniu intre drumul Bacriului și valea Cascadelor.','2025-08-09T19:02:17Z','2025-08-10T06:47:43Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBLsQo','Teren abandonat Petre Ispirescu × Margeanului','teren-abandonat-petre-ispirescu-margeanului',44.414959980361964,26.06175184248514,'Aici se afla un teren abandonat unde funcționa o carciuma care a ars. Acum se afla doar moloz și mașini parcate. Se poate amenaja un parculeț cu bănci, copaci pentru umbra și poate o fântână pentru a răcori zona. În zona nu prea exista parcuri/spatii verzi iar stația STB imediat lângă nu are niciun refugiu pentru umbra deci chiar ar mergi un spațiu verde.','2025-08-09T18:49:43Z','2025-08-10T06:47:54Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBLPdo','Strada Jiului','strada-jiului',44.4836472000274,26.041857004165653,replace('Toata strada arata de parca este uitata in timp. \nPe sensul spre Bucurestii Noi prima banda este de fapt parcare, deseori cu masini parcate in colturi de intersectie sau pe trecerile de pietoni. Trotuarele de pe ambele sensuri sunt pline de masini pentru ca nu exista stalpisori. De asemenea sunt pline de gropi, gauri, santuri, si exista portiuni foarte inclinate spre strada\nMasinile merg cu viteza mare pentru ca este un drum larg si drept, se fac devansari periculoase pe prima banda. Multi soferi raman pe banda a doua pentru ca prima banda este aproape impracticabila in ambele sensuri din cauza masinilor oprite sau care stau pe avarii.\nTrecerile de pietoni sunt foarte periculoase, mai ales ca nu sunt semaforizate, nu au masuri de calmare a traficului si cum mentionam mai devreme, viteza cu care se circula este foarte mare.\nTrotuarul din fata fostului depozit Pajura - Jiului este aproape impracticabil, este plin de vegetatie de pe terenul gol care se lasa peste trotuarul si asa minuscul. La intersectia Jiului cu Natatiei, unde se afla semaforul, trotuarul este fix cat sa incapa stalpul semaforului.\nAre o portiune de aproape 650m fara trecere nicio trecere de pietoni - de la Dridu pana in dreptul strazilor Sinca si Epuresti. Intersectia cu Natatiei desi este semaforizata, nu are trecere de pe un sens al celuilalt al strazii Jiului.\nIntersectia cu Bd.Gloriei, Bd. Bucurestii Noi, str. Strabuna este un haos la orice ora din zi. Se aud claxoane mereu de la cei care merg de pe Strabuna spre Gloriei ca nu li se acorda prioritate fata de cei care ies de pe Gloriei si fac stanga spre Bucurestii Noi in directia spre centru. Semaforizarile pentru pietoni sunt foarte scurte si la intervale lungi, iar cele pentru masini par foarte ineficiente.','\n',char(10)),'2025-08-09T18:25:20Z','2025-08-10T06:48:30Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBLIoB','Banda adiacenta Iuliu Maniu','banda-adiacenta-iuliu-maniu',44.43394904317712,26.026010513305664,'Transformarea acestei benzi cu sens unic pe care deseori sunt parcate masini in banda de autobuz/ciclism, aceasta intinzandu-se din apropierea strazii Iedului pana la intersectia Lujerului.','2025-08-09T18:19:46Z','2025-08-10T06:48:44Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gL8dQ','Sofia colt cu Ankara','sofia-colt-cu-ankara',44.459614798172346,26.093462705612186,'Un scuar nemarcat in care acum sunt ingramadite masini. Ar putea fi un spatiu verde, sau macar un trotuar marcat.','2025-08-09T18:07:22Z','2025-08-10T06:48:57Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J2n9C','Parc Theodor Pallady','parc-theodor-pallady',44.4134772976717,26.20257885428754,'In loc sa se ocupe zona de alte blocuri de 10-13 etaje, se poate face un parc pentru a asigura o zona verde amenajata în zona. A se considera orice loc liber de pe strada gura ariesului','2025-08-09T18:01:51Z','2025-08-10T06:49:17Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J2eHu','Gura Badicului','gura-badicului',44.420538987234835,26.203819589898192,replace('Este un spatiu amplu care ar putea fi ușor transformat într-un spațiu multifuncțional.\nParc, terenuri sport, locuri de joaca.\nSe construiește masiv și in scurt timp vor fi peste 5000 de familii in zona.','\n',char(10)),'2025-08-09T17:50:03Z','2025-08-10T06:49:52Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gL2bi','Bratarii','bratarii',44.418434424078825,26.198266980712063,replace('Spatiu verde, împădurit cu loc de joaca și terenuri de sport, care ar deservii toată zona Gurilor.\nAr funcționa că un plămân verde in toată zona care și așa total lipsită de verdeață.','\n',char(10)),'2025-08-09T17:52:20Z','2025-08-10T06:50:03Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J2UBy','Piața Romană','piaa-roman',44.44538515891052,26.097882986068726,'Mi-aș dori ca acest punct ultra central, și totodată un nod intermodal de transport public foarte important să fie mai verde (în momentul actual nu prea ai unde să stai la umbră cât aștepți autobuzul, iar trotuarul realizat doar din pavele este insuportabil de fierbinte vara).','2025-08-09T17:45:28Z','2025-08-10T06:50:26Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gKpte','Cartier giurgiului','cartier-giurgiului',44.38435377480767,26.0971212387085,'Întregul cartier este extrem de impanzit de masini. Ar trebui total refacut, pietonalizat si inverzit','2025-08-09T17:25:43Z','2025-08-10T06:50:40Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J1u8U','Pasarela istorica Grivita','pasarela-istorica-grivita',44.459309448751505,26.052780300378803,'Restaurare pentru o mai buna si usoara utilizare ai ei de catre toti oamenii, o solutie simpla pentru a traversa toate sinele fara a ocoli / a se expune riscului de a traversa pe sine ','2025-08-09T17:12:52Z','2025-08-10T06:50:55Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gKVNE','Parcul Eroilor Sanitari','parcul-eroilor-sanitari',44.43497176193724,26.072638206116014,'As dori sa fie amenajat si inegrat cu parcul Facultatii de Medicina unde studentii, personalul spitalului si pacientii sa poata sa se poata relaxa si sa ia o pauza de la greutati','2025-08-09T17:03:58Z','2025-08-10T06:51:29Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8IzODc','Locul pe unde iese Dambovita din Bucuresti','locul-pe-unde-iese-dambovita-din-bucuresti',44.3961367348865,26.222047805786136,'Propun crearea unei piste de biciclete care sa traverseze tot raul Dambovita si de asemenea propun largirea lui in asa fel incat sa existe cat mai multe zone de faleza unde te poti plimba.','2025-08-09T15:35:21Z','2025-08-10T06:52:08Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gJjbm','Aleea Barajul Lotru','aleea-barajul-lotru',44.42652438152996,26.166108335878786,'Aici exista o mare parcare intre mai multe blocuri. Propun reducerea locurilor de parcare, amplasarea unei fantani si a unor banci. Putem face din acest loc, loc public de intalnire','2025-08-09T15:33:45Z','2025-08-10T06:52:24Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gJbPi','Bulevardul Primaverii - zona Utopia Primaverii','bulevardul-primaverii-zona-utopia-primaverii',44.46833496884966,26.09054462290368,'Cartierul Primaverii este unul dintre cele mai frumose cartiere pe care le are acest oras, cu vile istorice si strazi inguste, cu catenele si restaurante. Piata despre care vorbesc este o mare parcare in acest moment. Avand in vedere lipsa unei piatete in cartier si ca langa aceasta parcare sunt restaurante si cafenele as propune eliminarea locurilor de parcare, introducerea unei piste de biciclete si amplasarea unei fantani si plantarea unor copaci sau unor garduri vii impreuna cu niste banci.','2025-08-09T15:24:02Z','2025-08-10T06:52:54Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8J1Ke8','Ferdinand si Pantelimon','ferdinand-si-pantelimon',44.445996450572366,26.133777711074806,'Recent, PS2, a defrisat spatiile verzi din fata blocurilor, intr-o actiune de ''ecologizare'', insa nu a mai revenit sa planteze gazon sau alte plante, lasand locurile sa se transforme in mici ''deserturi'' care nu fac decat sa creasca discomfortul termic resimtit in aceasta perioada. Mi-as dori ca primaria sa duca la bun sfarsit aceste proiecte, luand in considerare specii de vegetatie rezistente la caldura care sa si aduca  beneficii locuitorilor zonei in loc sa ii lase tot pe acestia sa isi reamenajeze spatiul distrus.','2025-08-09T16:50:21Z','2025-08-10T06:51:53Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gJAbm','Strada Edgar Quinet','strada-edgar-quinet',44.436001503485265,26.1011016368866,'Ca student al UNIBUC, mi-as dori sa vad aceasta strada pietonala, plina de activitate si de oameni ','2025-08-09T14:52:17Z','2025-08-10T06:53:16Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBBabF','Strada Ion Câmpineanu x Strada Academiei','strada-ion-cmpineanu-x-strada-academiei',44.43730381511632,26.098709106445316,'Strada Ion Câmpineanu x Strada Academiei = o parcare GIGANTICĂ in mijlocul orasului, cu masini pe toate sensurile. Mi-ar placea foarte mult sa vad aceasta intersectie regândita si sa avem parte de mai mult spațiu verde. :)','2025-08-09T13:32:40Z','2025-08-10T06:53:38Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBG2xb','Cinematograf Flamura','cinematograf-flamura',44.38918329029904,26.093087196350098,'O zonă cu mult spatiu verde, cu un trotuar care a fost odata larg, acum s-a redus spatiul pietonal pentru a se crea locuri de parcare. In primul rand, propun redeschiderea Cinematografului Flamura, avand rol cultural si de intalnire in cartier si in al doilea rand propun eliminarea locurilor de parcare si trasarea unor piste de biciclete conforme.','2025-08-09T15:29:39Z','2025-08-10T06:52:39Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gclwG','Parc nou Pache Protopopescu','parc-nou-pache-protopopescu',44.43940335115778,26.122280359268192,'Eliminata breteaua auto din dreptul DSP si facut parc/zona pietonala in locul ei.','2025-08-10T08:00:17Z','2025-08-10T08:10:06Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gcps8','Piata Delfinului','piata-delfinului',44.44438725852612,26.158824932117202,'Sa se transforme dintr-o parcare (din care jumatate parcheaza ilegal) intr-un loc verde si pietonal, adiacent pieței, eventual cu alte tarabe aditionale pietei. In momentul de față, ca pieton e aproape imposibil sa parcurgi zona fără să dai de vreun pericol (mașini care merg cu viteză pe strada rămasă strâmtă din cauza mașinilor parchate pe margine, tot felul de borduri, trotuare pe care se parcheaza si de care te poti impiedica etc.)','2025-08-10T08:07:46Z','2025-08-10T08:10:31Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gcjoA','Parcul Mantuleasa','parcul-mantuleasa',44.432624054835365,26.111594438552856,replace('Desfiintarea parcarilor si refecarea parcului Mantuleasa.\n\nDesfiintata breateaua auto dintre Mantuleasa si Dunarea Albastra','\n',char(10)),'2025-08-10T07:55:23Z','2025-08-10T08:10:50Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCQgK9','Parcul Popa Nan','parcul-popa-nan',44.43542025511037,26.125681400299076,'Eliminata breteaua rutiera din dreapta parcului (cea pe care nu circula STB-ul) si extins parcul.','2025-08-10T07:52:34Z','2025-08-10T08:11:03Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gci1W','Pietonalizare Strada Burghelea','pietonalizare-strada-burghelea',44.435780383848105,26.118031740188602,replace('Pietonalizata strada Burghelea pe segmentul Popa Soare - Mantuleasa.\n\nPermis accesul doar riveranilor cu limitarea vitezei la 5km/h.','\n',char(10)),'2025-08-10T07:50:09Z','2025-08-10T08:11:17Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gcmfQ','Parc Horei','parc-horei',44.44154820079547,26.124018430709842,replace('Desfiintare bretele auto si parcari de pe laterale si lasat o singura banda in regim shared-space, la nivelul trotuarului cu regim de viteza 5km/h.\n\nExtins parcul si zona pietonala.','\n',char(10)),'2025-08-10T08:02:20Z','2025-08-10T08:11:34Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Jt9eA','Parcul Delea Noua','parcul-delea-noua',44.43136749075111,26.1315393447876,'Eliminata parcarea improvizata dintre Calarasi si Matei Basarab si extins parcul.','2025-08-10T07:57:12Z','2025-08-10T08:10:40Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCQc4v','Piata Sfantul Stefan','piata-sfantul-stefan',44.434102428576125,26.11635804176331,replace('Extinderea parcului prin desfiintarea parcarilor improvizate aflate pe colturile parcului.\n\nDesfiintarea unui rand de parcari de pe lateralele parcului.\n\nAdus carosabilul la nivel cu accesul in parc si limitare de viteza la 20 km/h.','\n',char(10)),'2025-08-10T07:47:51Z','2025-08-10T08:11:57Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gcfNo','Parcul Izvorul Rece','parcul-izvorul-rece',44.43811672951695,26.116454601287845,replace('Introducerea de treceri de pietoni suplimentare pentru a usura accesul in parc.\n\nReducerea numarului de benzi auto.','\n',char(10)),'2025-08-10T07:44:22Z','2025-08-10T08:12:08Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Jstw8','Piata Rosetti','piata-rosetti',44.436256718370274,26.106423139572147,replace('Eliminarea unei benzi de circulatie pe fiecare sens.\n\nEliminata breteaua + parcarile dintre Dianei si Arghezi.\n\nMarit parcul din mijlocul intersectiei + treceri de pietoni pentru a permite accesul in parc si a pune in valoare statuia lui CA Rosetti.\n\nPe viitor, mutat tot traficul auto pe una din partile scuarului, cu transformarea celeleilate parti in zona pietonala.','\n',char(10)),'2025-08-10T07:42:21Z','2025-08-10T08:12:18Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gcdYu','Piata Mihail Kogalniceanu','piata-mihail-kogalniceanu',44.434548708270675,26.087862253189087,replace('Desfiintate parcarile si bretelele exterioare si transformata zona in spatiu pietonal.\n\nEliminat parapetele metalic din jurul scuarului. \n\nInchise accesurile de pe stradutele limitrofe dupa modelul strazii Pompiliu Eliade.\n\nPastrata o singura banda auto + cate o banda STB pe fiecare sens.','\n',char(10)),'2025-08-10T07:36:37Z','2025-08-10T08:12:44Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Jsgqy','Palatul Luigi Cazzavilan','palatul-luigi-cazzavilan',44.44261234985779,26.086671352386478,'Zona are deja un parculet, ceea ce e super. In schimb, palatul luigi cazzavilan zace abandonat in pofida arhitecturii sale superbe.','2025-08-10T07:28:55Z','2025-08-10T08:13:49Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCPIwq','Statia 311 (Sala Palatului)','statia-311-sala-palatului',44.43762420168943,26.095672845840458,'Locul, un desert de asfalt, are nevoie de copaci. Ar trebui sa fie o extensie a parcului. ','2025-08-10T07:08:07Z','2025-08-10T08:14:03Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JsgHq','Intersectie Mecet cu Traian','intersectie-mecet-cu-traian',44.43593309321489,26.121990680694584,'Momentan locul respectiv este o parcare. Ar merge facut un mini-parculet in loc sau macar inverzit.','2025-08-10T07:28:24Z','2025-08-10T08:14:24Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCPkwU','Starzile adiacente Ateneului','starzile-adiacente-ateneului',44.441033637477354,26.09610199928284,'Piatra cubica cu multi copaci si pietonal. In niciun caz masini. Ar putea fi posibila o ruta de bus (una deja exista). BUS only + bicicleta. Tot arealul ar beneficia de pietonizare. ','2025-08-10T07:14:05Z','2025-08-10T08:15:40Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gcPAy','Lacul Morii fara barci','lacul-morii-fara-barci',44.45109121644145,26.034851074218754,'Am dori sa existe ambarcațiuni destinate publicului larg pe lac si pontoane unde sa putem sa ne lansam propriile ambarcatiuni','2025-08-10T07:12:27Z','2025-08-10T08:16:05Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Js2g0','Bulevardul Magheru','bulevardul-magheru',44.43851228086303,26.100747585296634,'Este o autostrada care taie orasul ca o cale ferata. Integrarea acestui drum in oras se poate face doar prin reducerea benzilor, benzi unive, piste de bicicleta, extinderea spatiilor pietonale, creearea de spatii verzi. ','2025-08-10T07:10:49Z','2025-08-10T08:16:19Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gLsmO','Spatiul verde distrus de masini','spatiul-verde-distrus-de-masini',44.47590799422974,26.107474565505985,'Spatiul verde ar putea avea un impact pozitiv in zona, insa acesta este acum distrus de masini si de lucrari.','2025-08-09T19:52:49Z','2025-08-10T08:16:36Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb942yh','Intersectia Bucur','intersectia-bucur',44.421211886596424,26.107456565368924,'O reamenajare a parculetului degradat din fata Maternitatii Bucur si extins catre sud-vest unde carosabilul acum e ocupat de o parcare neconfigurata corespunzator. Asfel, spatiul verde merge extins, relationat eventual cu zona memorialului Colectiv si trasat treceri de pietoni care nu exista deloc in zona. Zona este difuza d.p.d.v spatial si functional si necesita o reconfigurare mai prietenoasa cu pietonii, avand in vedere ca sunt obiective de interes public in zona (maternitatea, unitate de educatie, fosta hala Pionierul care acum activitati sportive/recreative, locuire colectiva/individuala).','2025-08-08T13:56:29Z','2025-08-10T08:17:01Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Js1e8','Cinema Abandonat','cinema-abandonat',44.46277732019399,26.04539752006531,'Aceasta cladire abadonata sa se transforme in ceva folositor pentru comunitate','2025-08-10T07:10:30Z','2025-08-10T08:17:53Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8HD8Ae','Parc Dionisie Lupu','parc-dionisie-lupu',44.44402174991139,26.10089778900147,'Spatiu verde, ingrijit si curat, fara dale de beton sau porumbei. Fantana copiilor functionala. Loc pentru oameni, nu lasat in paragina. ','2025-08-08T13:59:21Z','2025-08-10T08:17:39Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb963A3','Spațiu verde sub asediu','spaiu-verde-sub-asediu',44.42314670861153,26.05532169342041,'În fiecare decadă mașinile au mușcat tot mai mult din spațiul verde, până s-a ajuns la o uriașă parcare. De fapt, acolo ar trebui să fie o zonă de joacă pentru copii din cartier, care nu au parc! Scoatem mașinile, plantăm!','2025-08-08T14:07:03Z','2025-08-10T08:18:59Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gKyei','Spatii verzi și terenuri de sport','spatii-verzi-i-terenuri-de-sport',44.420650818041956,26.203550508674407,'E un spatiu amplu care ar putea fi folosit că spatiu verde, Promenada, sport.','2025-08-09T17:46:32Z','2025-08-10T08:19:26Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbBB1VW','Zona verde/gradina urbana - cvartal','zona-verdegradina-urbana-cvartaldd',44.42775796368916,26.05565428733826,replace('Intr-o zona care este incojurata de bulevarde aglomerate, oamenii din zona au nevoie de spatii verde, asa cum a fost si gandit initial acest cvartal. \nAr fi minunat sa fie amenajat ca spatiu verde, ingrijit, cu bancute si/sau zona de gradina urbana. \n','\n',char(10)),'2025-08-09T13:16:32Z','2025-08-10T08:19:56Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb9Hz9U','Zona omv pipera','zona-omv-pipera',44.49227302077713,26.126622696472282,'Deși in zona sunt foarte multe birouri, toată zona nu este deloc prietenoasa cu pietoni, de la intersecția Dimitrie Pompeiu cu Petricani, pana la rond OMV Pipera, aproape ca nu sunt trotuare in unele zone, dar nu este deloc umbra, trafic foarte mare de mașini și praf. Ar putea fi gândit ca un spațiu mai prietenos cu pietoni, cu treceri de pietoni mai sigure, cu umbra și locuri de stat, cu trotuar, cu plante și copaci care sa scadă temperatura vara','2025-08-08T14:56:01Z','2025-08-10T08:23:05Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Iv0CU','Zona verde/gradina urbana - cvartal','zona-verdegradina-urbana-cvartal',44.42641712934597,26.055868864059452,replace('ntr-o zona care este incojurata de bulevarde aglomerate, oamenii din zona au nevoie de spatii verde, asa cum a fost si gandit initial acest cvartal. \nAr fi minunat sa fie amenajat ca spatiu verde, ingrijit, cu bancute si/sau zona de gradina urbana.','\n',char(10)),'2025-08-09T13:17:22Z','2025-08-10T08:23:25Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbAf8CD','Noul Centru Vechi','noul-centru-vechi',44.435128172369,26.111412048339844,'Zona Noului Centru Vechi din jurul strazilor Negustori-Plantelor incepe sa prinda contur. Insa ignorarea recomandarilor Bancii Mondiale de a o face complet pietonala face ca treaba sa para facuta doar pe jumatate. Zona nu va fi niciodata centrul vechi nou care promite sa fie daca in continuare se merge cu masina pe acolo. Bucurestenii trebuie sa inteleaga ca marile orase au mai multe zone fara trafic si nu e un capat de tara ca se mai inchide cate o portiune.','2025-08-08T22:40:07Z','2025-08-10T08:23:57Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb9kMPg','Parc Rocar','parc-rocar',44.39576788207617,26.088581814005344,'Amenajarea unui parc pe locul uzinei Rocar.','2025-08-08T20:33:47Z','2025-08-10T08:24:20Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8HmAFO','Intersecție strada Italiana','intersectie-strada-italiana',44.43847587076822,26.107839345932007,'E intersecția a vreo 6 străzi nu foarte circulate. Centrul intersecției e ocupat de mașini, de creează un fel de sens giratoriu din mașini. Ar merge verdeață, cartierul nu e prea verde.','2025-08-08T20:16:09Z','2025-08-10T08:25:00Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Hldh4','corbeni cu Armeneasca','corbeni-cu-armeneasca',44.440996093813546,26.11161589622498,'verdeață in mijlocul intersecției, nu stâlpișori de plastic','2025-08-08T20:10:50Z','2025-08-10T08:25:17Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5fvQzI','Str Jules Michelet','str-jules-michelet',44.443960472355236,26.098548173904422,'Deschisă publicului ','2025-08-08T19:26:45Z','2025-08-10T08:24:43Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJb9VhKS','Piața Spaniei','piaa-spaniei',44.4457391461839,26.10796232940629,'O zonă pietonală și de relaxare, nu un spațiu dedicat mașinilor (o mare parcare)','2025-08-08T18:01:01Z','2025-08-10T08:25:39Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gcJzC','Spatiu verde abandonat intre blocuri','spatiu-verde-abandonat-intre-blocuri',44.4614679190237,26.070964336395267,'As dori ca ascet loc sa se intansforme intr-un spatiu pentru oamenii din comunitate, in care acestia sa isi pata petrece timpul liber','2025-08-10T07:08:14Z','2025-08-10T08:26:03Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5g9e8u','Prea multe masini','prea-multe-masini',44.44401409022038,26.095222234725956,'Foarte multe masini in Piata Amzei care fac ca zona sa fie urata, mai degraba o piata balcanica de anii 2000.','2025-08-08T22:48:41Z','2025-08-10T08:26:44Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5g9ZzU','Piata Urbana','piata-urbana',44.43024034151566,26.06660842895508,'Din nou, o zona cu potential de a fi o piata urbana pietonala pe bune in loc de inca o parcare si spatiu complet subutilizat si neatractiv.','2025-08-08T22:42:18Z','2025-08-10T08:27:05Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8HRq22','O noua legătură de metrou','o-noua-legtur-de-metrou',44.49171606552777,26.126302569237446,'Sa fie continuata linia albastra cu o noua stația în zona OMV Pipera pentru a facilita accesul la zona de birouri și a încuraja lăsarea mașinii acasa. De asemenea la ora de vârf din zona aceea până la metrou Pipera (capăt de linie) se fac și 40 de minute în mașină/aurobuz','2025-08-08T14:59:02Z','2025-08-10T08:27:48Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5fx3Fk','Eliberarea Dâmboviței','eliberarea-dambovitei',44.42765835990977,26.10237836837769,'Mi-aș dori decopertarea planșeului Unirii pentru a face Dâmbovița vizibilă. Îmi doresc să fie amenajat un mare parc central în jurul râului, plin de poduri pietonale și poate cu bărcuțe','2025-08-08T20:32:45Z','2025-08-10T08:29:48Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5fvPZE','Scuar Dorobanti/Beller','scuar-dorobantibeller',44.46040353035227,26.09431028366089,'Transformarea unei zone betonate într-un spațiu verde','2025-08-08T19:25:31Z','2025-08-10T08:30:15Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gdDkI','Pictor Arthur Verona - Alexandru D. Xenopol','pictor-arthur-verona-alexandru-d-xenopol',44.44291860868653,26.103036946023263,'Doresc ca aceasta zona sa fie pietonala permanent.','2025-08-10T08:33:06Z','2025-08-11T05:47:08Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCTWiM','Republica','republica',44.43352438492111,26.186331758811953,replace('Aș dori ca acest loc să devină un nod intermodal modern care facilitează accesul ușor pentru pietoni la toate mijloacele de transport din zonă. Este unul din puținele locuri din București în care ai acces la tren, metrou, tramvai și autobuz. \n\nIdeal, mi-aș dori să văd cum ar arată acest loc dacă infrastructura feroviară ar fi mutată în subteran cu o stație complet nouă lângă sau sub stația de metrou existentă și cum ar fi să ai o singura stație din care să iei tramvaiul sau autobuzul către centru sau periferia Bucureștiului. ','\n',char(10)),'2025-08-10T09:07:09Z','2025-08-11T05:47:32Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Jvx4q','Refacere Calea Vacaresti','refacere-calea-vacaresti',44.41265456045724,26.11436247825623,'Modificarea parcarilor de la parcare diagonala la parcare orizontala. Mutarea locurilor de parcare pe prima banda. Spatiul dintre noile locuri de parcare orizontale si trotuar va deveni pista de bicicleta. Intersecția cu Strada V.V.Stancu devine sens giratoriu. La intersecția cu Bvd. Tineretului, banda pentru viraj la dreapta se transformă în pistă de biciclete in totalitate. La intersecția la Timpuri Noi, banda pentru viraj la dreapta pe Splaiul Unirii se transformă integral în pistă de biciclete, conectată cu viitoarea pistă din rețeaua principală a MasterPlan Velo.','2025-08-10T09:26:47Z','2025-08-11T05:48:18Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCUoyy','Bd. Râmnicu Sărat','bd-rmnicu-srat',44.41431128556181,26.143174000355334,'Pe toată lungimea lui să fie diapus un coridor verde de arbori  similar cu cel de pe str. Rm Vâlcea. Ar fi astfel mai multă umbră și s-ar mai recupera din spațiile verzi și arborii pierduți odată cu construirea locurile de parcare pe lateralele bulevardului','2025-08-10T09:32:27Z','2025-08-11T05:49:15Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Jw1rq','Refacere Bulevard Tineretului','refacere-bulevard-tineretului',44.409351368459006,26.112699508666996,'Locurile de parcare diagonale se transformă în locuri orizontale și sunt mutate către axul drumului. Pe locul rămas între locuri de parcare și trotuar se plasează o pistă de biciclete. Se păstrează o singură bandă de circulație, dar se lărgește puțin. Intersecția cu Strada Piscului, Calea Piscului și Strada Secerei se reprofilează total pentru a amplasa un sens giratoriu. ','2025-08-10T09:33:51Z','2025-08-11T05:49:37Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gdnOw','Refacere Bulevard Gheorghe Șincai','refacere-bulevard-gheorghe-incai',44.415811961699035,26.110467910766605,'Locurile de parcare orizontale se transformă în locuri de parcare orizontale și se mută către axul drumului. În spațiul rămas între locuri de parcare și trotuar se construiește o pistă de biciclete. Se desființează o bandă de circulație și stațiile de autobuz de pe trotuar. Autobuzul va circula pe linia de tramvai cel puțin până la intersecția Timpuri noi, așa cum o face deja parțial. ','2025-08-10T09:39:22Z','2025-08-11T05:50:18Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JwAWM','Banda de viraj la dreapta pentru bicicletă ','banda-de-viraj-la-dreapta-pentru-biciclet-',44.41650932588167,26.11305356025696,'Banda care în prezent e destinată virajului la dreapta mașinilor va fi transformaț integral în pista de biciclete, continuând proiectul Refacere Bulevard Gheorghe Șincai și conectându-l cu proiectul Refacere Calea Văcărești. Se formează un triunghi bulevarde refăcute: Calea Văcărești, Tineretului și Șincai.','2025-08-10T09:42:08Z','2025-08-11T05:50:50Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JwEUG','Șina de tramvai folosită și de autobuz și total refăcută','ina-de-tramvai-folosit-i-de-autobuz-i-total-refcut',44.40875355507531,26.096992492675785,'În primul rând, șina tramvaiului 19 este absolut distrusă de la Eroii Revoluției la Timpuri Noi și trebuie refăcută în integralitate. În al doilea rând, ar trebui folosită la comun cu autobuzele și stațiile folosite comun, pentru că oricum sunt în aceeași zonă. ','2025-08-10T09:44:48Z','2025-08-11T05:51:11Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCV8UA','O bandă transformată în pistă de biciclete','o-band-transformat-n-pist-de-biciclete',44.4114513311451,26.100790500640873,'Banda 1 de la Eroii Revoluției înspre Tineretului poate fi transformată în pistă de biciclete. La Tineretului, pista se poate conecta cu cea din proiectul Refacere Bulevart Tineretului la dreapta și cu cea Refacere Bulevar Gheorghe Șincai în față.','2025-08-10T09:46:52Z','2025-08-11T05:51:31Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCVK5v','Parcare de biciclete','parcare-de-biciclete',44.41378112851972,26.104738712310795,'Spațiul este nefolosit și ar putea găzdui ușor o parcare de 50 de biciclete.','2025-08-10T09:48:07Z','2025-08-11T05:51:49Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCVOXU','Arenele Romane ','arenele-romane-',44.41297643949487,26.092884778851616,replace('Reabilitare si trasformare in gradina de vara care sa poata fi utilizata dincolo de concertele programate acolo:\n-cinema in aer liber si/sau in interior daca spatiul permite\n-restaurante/cafenele - ar fi utilizate si pe timp de iarna\n-ludoteca - pe vreme caniculara sau ploioasa parintii ar putea aduce copiii aici daca\n(Am observat ca exista o intrare minim si la nivelul aleilor, adica accesul s-ar putea face lejer din parc, nu prin interior urcand treptele)','\n',char(10)),'2025-08-10T09:55:07Z','2025-08-11T05:58:53Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JwZi0','Bd. Geniului','bd-geniului',44.430002834617994,26.060525178909305,'Introducerea unei benzi unice STB, sunt 5 auto și haos. Refacerea zonei cu accent pe zone verzi, spațiu pietonal și un terminal multimodal M-STB tramvaie','2025-08-10T10:00:32Z','2025-08-11T05:59:08Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCVaPh','Lascar Catargiu','lascar-catargiu',44.44735877743926,26.0956272482872,'Piste de biciclete pe fiecare sens, nu avem nevoie de autostrada in mijlocul orasului.','2025-08-10T10:01:35Z','2025-08-11T05:59:20Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCVw6c','Banda de autobuz și de tramvai comună','banda-de-autobuz-i-de-tramvai-comun',44.40188592721264,26.121143102645878,'În locul unei bande de autobuz, autobuzele și tramvaiele vor circula pe șinele de tramvai. O bandă de circulație pe sens de mers va fi transformată în pistă de bicicletă separată cu bordură de 40/50 cm de trafic.','2025-08-10T10:09:58Z','2025-08-11T05:59:33Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5ge73A','Pistă de biciclete','pist-de-biciclete1',44.38787990665352,26.113332509994507,'Micșorarea benzilor pentru a facilita instalarea unei piste de bicicletă','2025-08-10T10:11:02Z','2025-08-11T06:00:10Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5ge87m','Strada Izvor','strada-izvor',44.42935926268969,26.08098648476995,replace('In prezent e un loc pustiu in care esti expus in bataia soarelui, masinile circula ca pe autostrada si ai senzatia ca esti la periferia industriala a unui oras.\n\n-ar fi frumos sa existe limitatoare de viteza (montate la distante mici) pentru ca nici un sofer nu cred ca va tine cont de indicatoare, dar cu siguranta va incetini la intalnirea limitatoarelor pentru a-si proteja masina.\n-arbori care atrag polenizatori plantati pe ambele trotuare asa incat sa creeze umbra dar si bariera de sunet naturala\n-plante locale plantate la baza arborilor pentru a pastra umiditatea in sol si a atrage mici vietati care sunt esentiale \n-NU gazon','\n',char(10)),'2025-08-10T10:11:46Z','2025-08-11T06:00:47Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCW9pz','Pistă de bicicletă ','pist-de-biciclet-',44.378843071839896,26.10997438778756,'Amplasarea unei piste de biciclete prin reîntrebuințarea unei benzi de circulație','2025-08-10T10:12:35Z','2025-08-11T06:01:09Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCWAR0','Sans giratoriu','sans-giratoriu',44.38756555684205,26.109845638275146,'Sens giratoriu și limitatoare de viteza pe bulevarde pentru separarea naturală a mașinilor','2025-08-10T10:13:24Z','2025-08-11T06:01:45Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCWDss','Refacere pistă de bicicletă ','refacere-pist-de-biciclet-22',44.38643121344404,26.092143129477982,'În prezent, această pista defunctă este inclusă ca parte deja existentă în Masterplanul Velo. Totuși, nu circulă nimeni pe ea pentru că este absolut inutilizabilă în foarte multe locuri. Este necesară refacerea ei pentru a prioritiza bicicleta, nu mașinile','2025-08-10T10:15:22Z','2025-08-11T06:02:06Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5geDsY','Str Edgar Quinet ','str-edgar-quinet-',44.4357187517988,26.100002594292786,replace('In prezent este o parcare murdara, pare ca nu se face mai deloc curat aici. \n\nZona e minunata de plimbare si petrecut timp (in special pt studenti), exista si o fantana cu vegetatie care da farmec zonei.\n\nAr fi frumos sa fie desfiintata parcarea, montate bancute din lemn si sa fie igienizat spatiul si apoi mentinuta curatenia.','\n',char(10)),'2025-08-10T10:19:18Z','2025-08-11T06:04:24Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JxpB6','Calea Victoriei Pietonală','calea-victoriei-pietonal',44.441210575861675,26.095039844512943,replace('Datorită numărului mare de persoane care trec pe Calea Victoriei și cafenelelor care au ocupat aproape tot spațiul pietonal, trebuie neapărat lărgit spațiul sau făcut pietonal. Am stat 2 minute să aștept oamenii să treacă pentru că era spațiu doar de o singură persoană dus și întors. \nTotodată, strada are un mare potențial cultural. Fiind mai intuitiv  să te bucuri de locații când mergi într-o singură direcție, nu aleator cum este în Centrul Vechi. \nAprovizionarea pentru cafenele/restaurante se poate face și cu paleți și oameni plătiți să le aducă, nu doar cu mașina în fața localului. \nExistă străzi alternative care se pot folosi pentru a accesa străzi mici (ex: Bld. Dacia, strada Amzei, strada Buzești etc.) \nPropun Calea Victoriei complet pietonală, cu zebre și semafoare doar la intersecții. \nDe asemenea, este foarte periculos pentru toată lumea când șoferii merg pe aici cu 100 la ora, pierd controlul volanului și intră în plin în oameni/localuri. ','\n',char(10)),'2025-08-10T10:34:44Z','2025-08-11T06:09:58Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gePO6','Intersecția Olteniței-Brâncoveanu','intersecia-olteniei-brncoveanu',44.398460137528254,26.109179235766053,replace('Intersecția este neprietenoasă pentru pietoni, cu treceri semaforizate ce țin o veșnicie roșu ca să treacă un număr infernal de mașini. Acest fapt este accentuat de prezenta stației de metrou.\nMajoritatea călătorilor sunt nevoiți să treacă strada de multe ori întrucât majoritatea locuințelor se află pe partea opusă, iar mulți trebuie să meargă o distanță considerabilă până la stația de autobuz de pe Brâncoveanu. ','\n',char(10)),'2025-08-10T10:44:11Z','2025-08-11T06:12:10Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCXLns','Desființarea Romexpo','desfiinarea-romexpo',44.47733955675566,26.064805984497074,'Romexpo ar trebui desființat și pe locul lui ar trebui constuit un frumos cartier verde. Poate purta chiar numele cartierul Romexpo, Presei sau, favoritul meu, Uranus pentru a onora memoria vechiului cartier','2025-08-10T10:47:39Z','2025-08-11T06:13:41Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5geeRo','Piata Constitutiei','piata-constitutiei',44.42694159200125,26.09158515930176,replace('In prezenta Piata Constitutiei este o parcare, nicidecum o piata. \n\nPropuneri:\n-transformare in parc cu arbori care sa creeze umbra (pawlonia, tei) \n-amplasare de bancute de lemn \n-montarea unei fantani mici care sa racoreasca aerul suplimentar pe timp de vara si sa fie si sursa de apa pentru pasari\n-NU gazon, ideal este sa fie vegetatie nativa pentru pastrarea umiditatii in sol','\n',char(10)),'2025-08-10T10:58:14Z','2025-08-11T06:14:01Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JyTlc','Intersectie Splaiul Unirii','intersectie-splaiul-unirii',44.425810166434005,26.104041337966922,replace('Plantare de arbori care sa umbreasca zona aceasta. In prezent pietonii sunt expusi direct soarelui pe timp de vara. \n\nStiu ca deja au fost plantati cativa, dar mai sunt zone care pot acomoda arbori.\n\nEliminare panouri publicitare.','\n',char(10)),'2025-08-10T11:03:51Z','2025-08-11T06:14:20Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gesYo','Bvd Regina Elisabeta','bvd-regina-elisabeta',44.43457468134848,26.091080904006958,'Montare de limitatoare de viteza pentru a scadea viteza de deplasare a masinilor care in prezent polueaza fonic o zona centrala a orasului aflata langa un parc. ','2025-08-10T11:11:22Z','2025-08-11T06:14:33Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8Jz2wo','Piata Universitatii','piata-universitatii',44.43480452123103,26.101058721542362,replace('-arbori \n-plante mici, flori, plante aromatice\n-mici fantani care sa aduca un plus de racoare pe timp de vara si sa fie sursa de apa pentru pasari\n-bancute de lemn, inclusiv bancute circulare in jurul trunchiurilor de copaci, dar care sa lase spatiu de crestere pentru copaci','\n',char(10)),'2025-08-10T11:17:24Z','2025-08-11T06:14:47Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5geupw','Piața Lahovary','piaa-lahovary',44.4454828353815,26.09998783598637,'Pietonalizare (se poate oare?), revitalizare a pieței, copaci, pavaje.. Cred ca toata zona Pietei Romane ar beneficia de creerea unui spatiu pietonal in zona din spate, dedicat evenimentelor culturale etc.','2025-08-10T11:19:37Z','2025-08-11T06:15:02Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCZ5XE','Intersecție Virtuții - Petre Popovat - Constructorilor','intersecie-virtuii-petre-popovat-constructorilor',44.452033236756755,26.046867370605472,'Intersecția asta este un haos total. Se fac accidente măcar lunar, și șicanări la ordinea zilei. Toată intersecția este o mare de beton imensă, și este mult trafic pietonal, fiind lângă parc, metrou, stația lui 41 și două magazine mari. Aș vrea să fie mai sigură și pentru pietoni, și pentru mașini. ','2025-08-10T11:32:14Z','2025-08-11T06:16:24Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCZ83W','Podul Ciurel','podul-ciurel',44.44591366282938,26.038627624511722,'Locuitorii de la Strada Dâmbovița încolo trebuie să parcurgă o mare de betoane și străzi făcute DOAR pentru mașini pentru a ajunge la metrou (petrache poenaru) sau stația lui 41 (pentru a ajunge la Crangasi). Trotuarele sunt de formă, se circulă cu viteză, și stația lui 41 de sub pasaj este amplasată foarte prost. Vara asta aproape am făcut insolație mergând până acolo și așteptând tramvaiul. Propun să fie mutată acea stație fix la intersecția cu Dâmbovița, deoarece nu cred ca locul curent ar deservi mai mulți oameni decât cel propus','2025-08-10T11:36:26Z','2025-08-11T06:17:24Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JzGb6','Gradina Japoneza - Herastrau','gradina-japoneza-herastrau',44.46823483963264,26.080555915832523,replace('-eliminare imprejmuire (mi se pare inutila si face accesul in gardina complicat)\n-refacere alei, podete si surse de apa in stil japonez\n-pastrare lampioane de piatra si poate se pot monta in interiorul acestora surse mici de lumina care sa fie functionale pe timp de noapte\n-toaletare arbori si inlocuirea arborilor uscati pastrand caracterul gradinii (cires japonez, prun japonez, artar japonez - are frunze visinii si creaza un contrast placut vizual)\n-podetul de lemn ar trebui inaltat (poate chiar schimbat in functie de starea lemnului) si vopsit fie in nuante naturale, fie rosu cum este specific gradinilor japoneze.','\n',char(10)),'2025-08-10T11:40:43Z','2025-08-11T06:17:40Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8JzNrO','Biruintei ','biruintei-',44.36447852379907,26.15267515182495,'Tortuare cu stalpisori de ambele parti ale drumului! ❤️','2025-08-10T11:48:39Z','2025-08-11T06:17:54Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gf7de','Mutarea statuii soldatului în mijlocul intersecției, în interiorul unui rond nou creat','mutarea-statuii-soldatului-n-mijlocul-interseciei-n-interiorul-unui-rond-nou-creat',44.41282316386111,26.163661479949955,replace('Vin cu această propunere în completarea unei propuneri anterioare de realizare a unui sens giratoriu în intersecția aferentă; până în anii ''70, statuia se afla în centrul intersecției (pe un soclu diferit ce-i drept, care nu știu dacă se mai poate reconstrui): https://www.facebook.com/groups/1059895724364530/?multi_permalinks=1429125790774853\n\nPropun mutarea Monumentului eroilor căzuți în primul și al doilea război mondial așa cum este cunoscut oficial pe vechiul amplasament de până în anii ''70. Prin realizarea rondului și amplasarea statuii acolo se poate pune mai bine în evidență monumentul, și poate constitui un punct de reper local mult mai vizibil și cu o simbolistică locală mult mai semnificativă.','\n',char(10)),'2025-08-10T11:49:58Z','2025-08-11T06:18:16Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCZyjA','Bulevardul Berceni','bulevardul-berceni',44.38451157281829,26.130445003509525,'Consider ca pe intreaga lungime a Bulevardului Berceni este posibila adaugarea pistelor de biciclete pe lateralul carosabilului care este destul de generos si acum. Toate gurile de metrou sunt situate pe lateralul bulevardului si dispun si de zone pentru biciclete deci ar facilita si accesul la transportul in comun','2025-08-10T12:26:54Z','2025-08-11T06:18:32Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCZzek','Strada Foisorului','strada-foisorului',44.41111411594146,26.121089458465576,'Mai mult spatiu pentru pietoni, este un magazin care are scarile pe trotuar - si trotuarul a fost si micsorat. De fapt toata zona foisorului ar trebui regandita pentru pietoni.','2025-08-10T12:28:48Z','2025-08-11T06:18:47Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8K0BG0','Poduri pe dambovita. - Splaiul Unirii','poduri-pe-dambovita-splaiul-unirii',44.411673585557175,26.119287014007572,'Aceste poduri de pe dambovita sunt foarte vechi si nu pot fi accesate de persoane cu disabilitati. Este ramasa pe o rampa un grafitti foarte frumos pe care l-as introduce in proiect. Multe persoane trec acest pod si se bucura de priveliste, insa merita ajutat - consider ca se poate intinde ca proiect pentru toata Dambovita.','2025-08-10T12:31:24Z','2025-08-11T06:19:22Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8K0OUk','Splaiul unirii NU autostrada','splaiul-unirii-nu-autostrada',44.4096885938261,26.121207475662235,'Splaiul unirii este o strada pentru masini cat o autostrada: un pericol pentru pietoni deoarece se merg cu viteze mari, se simte un miros neplacut si vara este sauna - avem nevoie de gradini urbane.','2025-08-10T12:36:17Z','2025-08-11T06:19:54Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8K09bo','ȘOSEAUA DOBROEȘTI ','oseaua-dobroeti-',44.44425509212102,26.166971206857852,replace('Cum intrii pe șoseaua Dobroești vezi mașini parcate pe ambele trotuare până la  pod Dobroești intrarea în comună. Zona aparține de sector 2 până la pod, o zonă uitată de primărie.\nAm tot făcut reclamații dar nimic din partea primăriei sector 2.\nSe tot construiesc blocuri pe Șoseaua Dobroești și dispare orice loc liber pe trotuar in viitorul apropiat din cauza mașinilor. Situația este cat se poate de urgentă deoarece în comuna Dobroești sunt în execuție vreo 10 blocuri de 10 etaje.\nSa intrii in București prin Șoseaua Dobroești e un adevărat calvar din cauza mașinilor care pe lângă că ocupă trotuarele ocupă și prima bandă de circulație.HAOS.\nAs vrea sa vad trotuarele libere cu stâlpișori și flori și copaci verzi de-a lungul șoselei, de asemenea prima bandă de circulație sa fie eliberată de mașini pentru a circula autobuzele.','\n',char(10)),'2025-08-10T12:28:55Z','2025-08-11T06:19:08Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gfOYW','Gradinile Blocurilor de pe Bulevardul 1 Mai','gradinile-blocurilor-de-pe-bulevardul-1-mai',44.419390654550895,26.045815944671634,'Exista deja initiative pentru mici gradini urbane in cartierul Drumul Taberei. Pe Bulevardul 1 Mai fiecare bloc dispune de spatiu verde umbros unde se pot amenaja mici zone comunale cu mese si paturi de flori/ plante. Comunitatea cartierului deja petrece timp in aceste spatii insa pe cateva banci si pe scaune aduse de acasa. ','2025-08-10T12:41:09Z','2025-08-11T06:20:33Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCa3y5','Strada Lascar','strada-lascar',44.43723954186742,26.10732436180115,'La acest moment este ca o cursa cu obstacole sa mergi pe aceasta strada din cauza santierului si a gunoiului. Masinile parcate pe trotuarul si asa ingust nu ajuta nici ele. Este si foarte periculos, soferii venind cu viteza pe strada si avand vizibilitate redusa din cauza masinilor parcate. Niste stalpisori si refacere a trotuarului ar ajuta. ','2025-08-10T12:32:31Z','2025-08-11T06:19:42Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8K1Eyy','Statia de metrou 1 Decembrie 1918','statia-de-metrou-1-decembrie-1918',44.40993293668658,26.1770510673523,replace('Doua din cele patru guri ale statiei se afla efectiv in parcari. Se vede foarte clar ca, in mod normal, acolo trebuia sa fie pur si simplu continuarea troturului dinspre piata Trapezului unde se afla celelalte doua guri de metrou, pe ambele parti ale bvd. Theodor Pallady.\n\nMi-as dori transformarea in trotuar parcarilor espective, eventual, daca este posibil, cu cat mai mult spatiu verde, copacii care exista deja si care fac totusi umbra fiind insuficienti. Numarul foarte mare de oameni care folosesc statia nu ar mai fi nevoiti sa mearga printr-o parcare betonata si sa se fereasca de masini.','\n',char(10)),'2025-08-10T13:03:29Z','2025-08-11T06:21:46Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('oLHtOefD7nkFljdU8K22tW','Sens unic și lărgirea trotuarelor pe Drumul Jilavei ','sens-unic-i-lrgirea-trotuarelor-pe-drumul-jilavei-',44.3761281418909,26.132532114588688,'Mi ar plăcea ca Strada Drumul Jilavei, care face accesul dinspre zonele rezidențiale Viva/ Kristal/ Metalurgiei către Metrou Apărătorii Patriei să fie cu sens unic dinspre complex înspre metrou și să existe trotuare pe ambele părți ale drumului. ','2025-08-10T13:36:57Z','2025-08-11T06:21:57Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5ghgUC','Parc Universitatea Spiru Haret','parc-universitatea-spiru-haret',44.380066663357574,26.133867502212528,'Aici era candva un parc, care din pacate a fost transformat in parcare. Zona e plina de trotoare inguste, beton si ciment, iar vara se simte lipsa copacilor, asa ca reconstruirea acestui parc ar fi o idee foarte buna, dar si plantarea copacilor si largirea trotuarelor din zona','2025-08-10T15:39:31Z','2025-08-11T06:23:21Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5ghvjC','Reorganizare Cal. Grivitei si Bd. Bucurestii Noi','reorganizare-cal-grivitei-si-bd-bucurestii-noi',44.464757064347445,26.05489253997803,'In momentul de fata, pe un procent mare din bd. Bucurestii Noi si Calea Grivitei, in ambele sensuri, banda 1 este ocupata de masini parcate. Calea Grivitei are cele doua (3 in unele locuri) benzi pe sens mult mai late decat ar fi nevoie, drept pentru care nu se respecta limita de viteza. Prin ingustarea benzilor si inlocuirea uneia (unde este posibil) cu banda dedicata pentru STB, se poate face loc chiar si pentru o pista de biciclete. Valabil si pe Buc. Noi, pe toata lungimea lui. Limita de viteza este mare si oricum nu e respectata, se circula si cu 80-100 km\h intre Straulesti si Laminorului, pe ambele sensuri.','2025-08-10T16:07:24Z','2025-08-11T06:23:58Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('nP5GIt0J2mhTNRaq5gi63M','Soseaua Fundeni - spitale IOB si Fundeni','soseaua-fundeni-spitale-iob-si-fundeni',44.463087774187365,26.155184164140305,replace('Pe partea cu spitalele este o fasie de pamant intre trotuar si imprejmuirea spitalelor unde sunt cativa pomi. \n\nAs propune sa fie toaletata acea zona, ingrijita si mentinuta, instalate banci, cosuri de gunoi si surse de apa potabila.\n\nIn acea zona sunt foarte multi pacienti cronici (batrani de multe ori) sau care urmeaza tratament agresive care se deplaseaza cu RATB si au nevoie de banci, spatiu de asteptare, umbra si de unde sa bea apa.\n\nAcum e o zona mica verde care e plina de gunoaie si e total neingrijita si nefolosita.','\n',char(10)),'2025-08-10T16:30:13Z','2025-08-11T06:24:32Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCoE4a','Strand Cara','strand-cara',44.41732451159664,26.162552144616203,'Strandul Cara este in paragina de ani de zile. Nu mi s-ar parea o idee rea sa fie renovat si curatat, ca sa poata fi folosit din nou de locuitorii cartierului. O alternativa ar fi transformarea acestuia intr-un parculet linistit si umbrit de arbori','2025-08-10T17:53:56Z','2025-08-11T06:24:49Z',NULL,NULL,NULL,NULL,NULL);
INSERT INTO geopoints VALUES('U2gTStYh0IVwUEOJbCsIcP','Acces zona lac','acces-zona-lac',44.46116927955635,26.03530436754227,'Niste accese adecvate din strazi pana catre pista din jurul lacului, ar fi perfect, momentan extista cateva prin zonele ocolitoare i.e mehadiei, direct din crangasi sau din zona opusa departata ','2025-08-10T19:29:20Z','2025-08-11T06:25:20Z',NULL,NULL,NULL,NULL,NULL);
